import type { Drill } from "./types";

// Sales / mid drills, keyed by module slug — 25 per module.
// Pitched at a sales or marketing manager: forecast calls, coaching reps,
// campaign readouts, launch coordination, deal reviews, escalations, and
// quota/territory conversations. Merged into course.ts.
export const SALES_MID_DRILLS: Record<string, Drill[]> = {
  "lead-with-the-point": [
    {"id":"lead-sales-mid-01","level":"mid","profession":"sales","title":"The buried forecast change","scenario":"Your weekly forecast email to the VP of Sales needs to say that commit dropped $180k because the Meridian deal slipped. Your draft opens with three paragraphs of pipeline color before the number changes.","task":"Write a 2-3 sentence forecast update that leads with the new commit number.","tips":["Sentence one: the new number and the delta.","The deal-level story is support, not the opener.","A VP scans for the change first — give it to them."],"focus":["clarity","structure"],"placeholder":"Commit is down $180k to $1.42M —"},
    {"id":"lead-sales-mid-02","level":"mid","profession":"sales","title":"The slipped anchor deal","scenario":"Your largest Q3 deal — $400k with Halvorsen — just slipped to Q4 after their CFO froze new spend. You need to tell your CRO in Slack, and your instinct is to walk through the whole call first.","task":"Write a Slack message that states the slip and the impact in the first sentence.","tips":["Lead with what happened and what it does to the quarter.","The call recap belongs below the headline.","Include the one next step you're taking."],"focus":["clarity","impact"],"placeholder":"Halvorsen ($400k) slipped to Q4 — their CFO froze new spend."},
    {"id":"lead-sales-mid-03","level":"mid","profession":"sales","title":"The escalation that hides its ask","scenario":"An at-risk strategic account needs an exec sponsor call this week or the renewal is in real danger. Your email to the CRO recounts six months of account history before asking for the 30 minutes.","task":"Rewrite the escalation so the ask — a 30-minute exec call this week — is sentence one.","tips":["Lead with the specific ask and the deadline.","One sentence of why, then the history if needed.","Make it possible to say yes from the first line."],"focus":["clarity","impact"]},
    {"id":"lead-sales-mid-04","level":"mid","profession":"sales","title":"The campaign readout warm-up","scenario":"Your paid-social pilot sourced $1.2M in pipeline at half the cost per opportunity of events. But your readout to leadership opens with audience definitions and attribution methodology.","task":"Write the opening 1-2 sentences of the readout, leading with the result.","tips":["Headline first: pipeline sourced and cost versus benchmark.","Methodology answers questions — it doesn't open the meeting.","If they hear only one sentence, make it the outcome."],"focus":["impact","concision"],"placeholder":"The paid-social pilot sourced $1.2M in pipeline at half the cost per opp of events."},
    {"id":"lead-sales-mid-05","level":"mid","profession":"sales","title":"The discount approval buried in backstory","scenario":"You need your VP to approve a 20% discount by Friday to close a $300k deal against an aggressive competitor. Your draft opens with the deal's four-month history.","task":"Write a 2-3 sentence approval request that puts the ask and deadline first.","tips":["First line: approve X% on deal Y by Friday.","One sentence of justification — competitor, value at stake.","History is available on request, not in the opener."],"focus":["clarity","structure"],"placeholder":"Requesting approval for 20% on the Brightline deal ($300k) by Friday —"},
    {"id":"lead-sales-mid-06","level":"mid","profession":"sales","title":"The rep-performance flag","scenario":"One of your AEs has missed quota three straight quarters and coaching hasn't moved the numbers. You're telling your VP you want to start a formal plan, but your draft eases in with praise and hedging.","task":"Write a message that states your recommendation in the first sentence.","tips":["Lead with the recommendation, not the sandwich.","The three-quarter record is your evidence, one line.","Name the decision you need from the VP."],"focus":["clarity","impact"]},
    {"id":"lead-sales-mid-07","level":"mid","profession":"sales","title":"The renewal-risk headline","scenario":"A top-10 account worth $250k ARR told their CSM they're evaluating a competitor at renewal. Your heads-up to leadership starts with how good the relationship has historically been.","task":"Write a 2-sentence alert that leads with the risk and the dollar figure.","tips":["Risk and ARR in sentence one.","History of the relationship is context, not the point.","Say what you're doing about it in sentence two."],"focus":["impact","precision"],"placeholder":"Northgate ($250k ARR) is actively evaluating a competitor at renewal."},
    {"id":"lead-sales-mid-08","level":"mid","profession":"sales","title":"The coverage warning","scenario":"Pipeline coverage for next quarter has fallen to 1.8x against your 3x target, and it needs action now — more top-of-funnel spend or a lower plan. Your draft to the VP wanders through pipeline-by-stage detail first.","task":"Write an opener that leads with the coverage number and the decision it forces.","tips":["The number and the gap go first.","Name the fork: invest in pipeline or reset the plan.","Stage-by-stage detail supports; it doesn't lead."],"focus":["precision","clarity"],"placeholder":"Q4 coverage is 1.8x against a 3x target — we need to decide now:"},
    {"id":"lead-sales-mid-09","level":"mid","profession":"sales","title":"The launch-date slip announcement","scenario":"Product just told you the launch your team has been selling toward slips two weeks. Reps have demos booked against the old date. Your draft to the team opens with the reasons before the new date.","task":"Write a 2-3 sentence team message that leads with the new date and what to do about booked demos.","tips":["New date first — that's what changes their week.","Then the one action: what to tell prospects.","Reasons come last and short."],"focus":["clarity","structure"]},
    {"id":"lead-sales-mid-10","level":"mid","profession":"sales","title":"The win that opens with the saga","scenario":"Your team just closed the biggest logo of the year — $600k with a marquee brand. Your announcement draft spends four sentences on the eight-month journey before naming the win.","task":"Write an announcement that leads with the win, then credits the work in a sentence.","tips":["The outcome is the headline: logo, size, what it proves.","The journey is one supporting sentence, not four.","Name who drove it — recognition lands better after a crisp headline."],"focus":["impact","concision"],"placeholder":"We just signed Corvex — $600k, our biggest logo this year."},
    {"id":"lead-sales-mid-11","level":"mid","profession":"sales","title":"The headcount request","scenario":"Your SDR team is at capacity and inbound leads are aging past the SLA. You want one more SDR approved this quarter. Your draft to the VP describes the workload problem for two paragraphs before asking.","task":"Write a request that puts the ask — one SDR req this quarter — in the first sentence.","tips":["Lead with the ask and the timing.","One line of evidence: lead aging against SLA.","End with the cost of waiting, briefly."],"focus":["clarity","impact"],"placeholder":"I'm asking for one additional SDR req this quarter."},
    {"id":"lead-sales-mid-12","level":"mid","profession":"sales","title":"The one-line answer the CMO needs","scenario":"The CMO pings you for a board-slide input: how much pipeline did the webinar series source this half? You know it's $840k. Your draft reply explains the attribution model before giving the number.","task":"Write a reply that gives the number first, then one caveat if needed.","tips":["Answer in the first three words.","One caveat maximum, after the number.","They're building a slide — give them something quotable."],"focus":["concision","precision"],"placeholder":"$840k sourced pipeline this half —"},
    {"id":"lead-sales-mid-13","level":"mid","profession":"sales","title":"Will you hit the number?","scenario":"The CFO asks you directly in a thread: will your team hit the Q3 number, yes or no? You believe yes, with one deal as the swing factor. Your draft reply gives three paragraphs of pipeline context first.","task":"Write a reply that answers yes or no in the first word, then names the swing factor.","tips":["Verdict first: yes, no, or a bounded probably.","Name the single deal or risk it hinges on.","Don't make a CFO excavate your answer."],"focus":["clarity","precision"],"placeholder":"Yes — with one caveat:"},
    {"id":"lead-sales-mid-14","level":"mid","profession":"sales","title":"The deal-review verdict","scenario":"After a deal review, your call is to disqualify the Ostrander opportunity — no budget, no exec sponsor, six months of stalling. Your write-up to the rep and your VP walks through every meeting before landing on the verdict.","task":"Write a summary that states the verdict first, then the two decisive reasons.","tips":["Verdict in sentence one: disqualify and remove from forecast.","Two reasons, one line each.","The meeting-by-meeting history is an appendix, not the message."],"focus":["structure","clarity"]},
    {"id":"lead-sales-mid-15","level":"mid","profession":"sales","title":"The SLA breach flag","scenario":"Marketing-sourced leads are sitting untouched for four days on average against a 24-hour SLA, and it's costing conversions. You're raising it with the sales managers, but your draft opens diplomatically about how busy everyone is.","task":"Write a message that leads with the breach and the ask.","tips":["First sentence: the number against the SLA.","Then the one ask: what changes this week.","Diplomacy is fine — after the point, not before it."],"focus":["clarity","precision"],"placeholder":"Leads are averaging 4 days to first touch against our 24-hour SLA."},
    {"id":"lead-sales-mid-16","level":"mid","profession":"sales","title":"The territory change announcement","scenario":"You're moving two enterprise accounts from one rep's patch to another's to balance load. Both reps will read this message. Your draft buries the actual change under paragraphs of rationale.","task":"Write a 2-3 sentence announcement that states the change first, effective date included.","tips":["The change and the date go first.","One sentence of rationale — balance, not performance.","Offer the conversation: happy to talk it through 1:1."],"focus":["clarity","structure"]},
    {"id":"lead-sales-mid-17","level":"mid","profession":"sales","title":"The quota-relief ask","scenario":"A rep inherited a gutted territory mid-quarter and you're asking your VP for a one-quarter quota adjustment. Your draft opens with a long defense of the rep's work ethic before the actual request.","task":"Write a request that leads with the specific adjustment you want.","tips":["Ask first: adjust X's Q3 quota from A to B.","Ground it in the territory change, one line.","Character references don't move quotas — facts do."],"focus":["clarity","precision"],"placeholder":"I'm requesting a one-quarter quota adjustment for Dana: $310k to $220k."},
    {"id":"lead-sales-mid-18","level":"mid","profession":"sales","title":"The event recap that leads with logistics","scenario":"Your booth at the industry conference produced 62 qualified conversations and 9 opportunities worth $700k in early pipeline. Your recap email opens with how the booth setup went.","task":"Write a recap opening that leads with the pipeline result.","tips":["Outcome first: opportunities and pipeline value.","Logistics and anecdotes are for the appendix.","Tie the number to the spend if you have it."],"focus":["impact","precision"],"placeholder":"The conference produced 9 opportunities worth ~$700k in early pipeline."},
    {"id":"lead-sales-mid-19","level":"mid","profession":"sales","title":"The customer-exec email","scenario":"You need 30 minutes with your customer's CFO to walk through the renewal business case before their budget cycle closes. Your draft email spends two paragraphs on partnership pleasantries before the request appears.","task":"Write a 3-sentence email that makes the request and the reason clear in the first line.","tips":["Ask for the meeting and name why now — budget cycle.","One sentence on what they'll get from the 30 minutes.","Courtesy stays; it just doesn't lead."],"focus":["clarity","audience"]},
    {"id":"lead-sales-mid-20","level":"mid","profession":"sales","title":"The competitor price-cut heads-up","scenario":"A competitor just cut list price 15% and two of your active deals mentioned it within a day. Your note to the team and your VP starts with speculation about the competitor's strategy.","task":"Write a heads-up that leads with what changed and what reps should do today.","tips":["Fact first: the cut and where it's showing up.","Then the play: what reps say in live deals.","Strategy speculation can wait for the team call."],"focus":["clarity","impact"],"placeholder":"Vantiv cut list price 15% — it's already come up in two live deals."},
    {"id":"lead-sales-mid-21","level":"mid","profession":"sales","title":"The handoff to customer success","scenario":"You're handing a newly closed account to CS. One thing matters most: the buyer expects the integration live in 30 days and will escalate if it isn't. Your handoff doc opens with a friendly account overview.","task":"Write a handoff opening that leads with the one commitment CS must not miss.","tips":["First line: the commitment and the consequence.","Everything routine can follow.","If they read one line, it should be the 30-day clock."],"focus":["clarity","impact"],"placeholder":"One thing cannot slip: the buyer expects integration live in 30 days."},
    {"id":"lead-sales-mid-22","level":"mid","profession":"sales","title":"The mid-quarter upgrade","scenario":"Two deals accelerated and your commit just moved up $250k with six weeks left. Good news — but your draft to the VP buries it under caveats about deals that might still wobble.","task":"Write a 2-sentence update that leads with the raise, then the one real risk.","tips":["Lead with the new commit and the delta.","Pick the single risk worth naming — not all of them.","Good news deserves a headline too."],"focus":["clarity","concision"],"placeholder":"Commit is up $250k to $1.9M —"},
    {"id":"lead-sales-mid-23","level":"mid","profession":"sales","title":"The redline chase","scenario":"A $200k deal is stuck because the customer's legal team has held redlines for two weeks. You're writing to your champion to get it moving, and your draft opens with three apologies for pestering them.","task":"Write a follow-up that leads with the ask and a concrete date.","tips":["Ask first: redlines back by Thursday to keep the signature date.","Tie the date to something they want — their go-live.","Cut the apologies; one courteous line is enough."],"focus":["clarity","impact"]},
    {"id":"lead-sales-mid-24","level":"mid","profession":"sales","title":"The two-options decision email","scenario":"You need your CRO to choose by Friday: keep the mid-market team on the current comp plan or move to the new accelerator model before Q4. Your draft explains six months of comp analysis before presenting the choice.","task":"Write an email that opens with the decision and deadline, then the two options in a line each.","tips":["Line one: the decision needed and by when.","Option A and Option B, one sentence each, with your lean.","Analysis is an attachment, not an opener."],"focus":["structure","clarity"],"placeholder":"Need your call by Friday: current comp plan or the accelerator model for Q4."},
    {"id":"lead-sales-mid-25","level":"mid","profession":"sales","title":"The wrong-price mistake","scenario":"You quoted a customer last year's pricing in writing — 12% below current list. You've decided to honor it this once and need to tell your VP. Your draft opens with a long explanation of how the old deck ended up in the email.","task":"Write a 2-3 sentence message that leads with the mistake, the cost, and your fix.","tips":["State it plainly: what happened, what it costs, what you're doing.","Sentence one carries the news — no wind-up.","Owning it fast reads as competence, not weakness."],"focus":["clarity","impact"],"placeholder":"I quoted Fairmont last year's pricing by mistake — 12% below list, about $18k."}
  ],
  "start-with-the-audience": [
    {"id":"audience-sales-mid-01","level":"mid","profession":"sales","title":"MQL quality, explained to the floor","scenario":"Reps are complaining that marketing leads are junk. You've dug in: the scoring model over-weights webinar attendance. Your draft to the sales floor is full of scoring thresholds and attribution terms they don't use.","task":"Rewrite the explanation in 3-4 sentences a rep cares about: what changed and what it means for their queue.","tips":["Lead with their stake: fewer junk leads in your queue starting Monday.","Translate scoring jargon into 'which leads you'll see'.","Say what to do with the old ones."],"focus":["audience","clarity"]},
    {"id":"audience-sales-mid-02","level":"mid","profession":"sales","title":"Campaign readout for the CFO","scenario":"You're presenting the demand-gen quarter to the CFO. Your slides talk impressions, CTR, and MQL volume. The CFO thinks in pipeline dollars, cost per dollar of pipeline, and payback.","task":"Write the 2-3 sentence summary you'd open with, in the CFO's terms.","tips":["Convert activity metrics into pipeline dollars and cost.","One number the CFO can repeat to the board.","Kill any acronym you'd have to define."],"focus":["audience","precision"],"placeholder":"We generated $2.1M in pipeline at $0.09 per pipeline dollar —"},
    {"id":"audience-sales-mid-03","level":"mid","profession":"sales","title":"Forecast categories for a new AE","scenario":"Your new AE just put every open deal in 'commit' because they're optimistic about all of them. They've never worked in a forecast-disciplined org. You need to explain commit versus best case versus pipeline.","task":"Write a 3-4 sentence explanation pitched at someone who has never forecast before.","tips":["Define each category by what you'd bet on it, not by CRM field names.","Explain why over-committing hurts them personally.","Give one test: would you stake your credibility on this closing?"],"focus":["audience","clarity"],"placeholder":"Commit means you'd stake your name on it closing this quarter."},
    {"id":"audience-sales-mid-04","level":"mid","profession":"sales","title":"Field feedback, translated for product","scenario":"Three deals stalled this quarter over the same missing capability. You want product to care, but your draft is deal gossip — names, personalities, quotes. Product needs the pattern: use case, segment, revenue blocked.","task":"Write a 3-sentence summary for the product team in their terms.","tips":["Lead with the pattern, not the anecdotes.","Quantify: how many deals, how much revenue, which segment.","Describe the use case, not the customer's mood."],"focus":["audience","precision"],"placeholder":"Three mid-market deals worth $520k stalled this quarter on the same gap:"},
    {"id":"audience-sales-mid-05","level":"mid","profession":"sales","title":"The delay email a customer can read","scenario":"An integration your customer is waiting on slipped because of an internal dependency between two engineering teams. Your draft to the customer explains your org chart. They only care about their go-live.","task":"Write a 2-3 sentence customer email about the delay in their terms.","tips":["Lead with the new date and what stays on track.","Cut internal team names and dependencies entirely.","Say what you're doing to protect their go-live."],"focus":["audience","clarity"]},
    {"id":"audience-sales-mid-06","level":"mid","profession":"sales","title":"The comp-plan change, in paycheck terms","scenario":"Finance approved a new comp structure: accelerators start at 100% attainment instead of 90%, and the multi-year kicker doubles. Your draft to the team quotes the plan document verbatim.","task":"Rewrite the announcement in 3-4 sentences focused on what changes in a rep's paycheck.","tips":["Lead with the headline in money terms: what pays more, what pays later.","One concrete example: a rep at 105% attainment earns X versus Y.","Point to the doc for the fine print — don't paste it."],"focus":["audience","clarity"]},
    {"id":"audience-sales-mid-07","level":"mid","profession":"sales","title":"The ICP brief for SDRs","scenario":"You've refined the ideal customer profile: operations leaders at logistics companies with 200-2,000 employees running legacy dispatch software. Your draft brief is a strategy memo. SDRs need to know who to call and what to say in the first ten seconds.","task":"Write a 3-4 sentence brief an SDR can act on today.","tips":["Lead with who to call: title, industry, size.","Give the one pain that opens the conversation.","Name what disqualifies a prospect fast."],"focus":["audience","concision"],"placeholder":"Call ops leaders at logistics companies, 200-2,000 employees, still on legacy dispatch."},
    {"id":"audience-sales-mid-08","level":"mid","profession":"sales","title":"The attribution fight, for the CEO","scenario":"Sales and marketing are arguing over who sourced a $900k deal, and the CEO asked what's going on. Your draft relitigates the touchpoint history. The CEO wants to know if the pipeline number is trustworthy and whether the teams are working together.","task":"Write a 2-3 sentence answer pitched at what the CEO actually cares about.","tips":["Answer the real question: is the number reliable and is the process fixed?","Skip the touchpoint archaeology.","One sentence on the fix going forward."],"focus":["audience","clarity"]},
    {"id":"audience-sales-mid-09","level":"mid","profession":"sales","title":"The renewal case for the economic buyer","scenario":"Your renewal deck was built for the admin who uses the product daily — feature adoption charts, usage stats. But the decision-maker is their CFO, who cares about cost avoided and risk reduced.","task":"Write the 2-3 sentence renewal argument aimed at the CFO, not the admin.","tips":["Translate usage into money: hours saved, cost avoided, risk reduced.","One defensible number beats five adoption charts.","Frame the renewal as protecting a return, not buying a tool."],"focus":["audience","impact"],"placeholder":"This year the platform saved your team roughly 1,100 hours —"},
    {"id":"audience-sales-mid-10","level":"mid","profession":"sales","title":"CRM hygiene, in their stake","scenario":"You need reps to update deal stages and close dates weekly. Your draft lectures about data quality and reporting needs — reasons that matter to you, not them. Their stake: bad data means their deals get challenged in forecast calls and their pipeline gets discounted.","task":"Rewrite the ask in 2-3 sentences framed around what the rep gains.","tips":["Lead with their benefit: clean deals sail through forecast review.","Name the cost to them of stale data — discounted pipeline, more scrutiny.","Keep the ask to one specific habit."],"focus":["audience","impact"]},
    {"id":"audience-sales-mid-11","level":"mid","profession":"sales","title":"Win/loss insight in product language","scenario":"You reviewed 20 losses and found a theme: buyers loved the product but the security questionnaire took three weeks to complete each time. You're writing to the product and security teams, who never see deals.","task":"Write a 3-sentence note that translates the sales pain into terms they can act on.","tips":["Lead with the operational fact: three weeks per questionnaire, 20 deals affected.","Frame the ask as a repeatable artifact, not 'help us sell'.","Quantify the revenue that waited on it."],"focus":["audience","precision"]},
    {"id":"audience-sales-mid-12","level":"mid","profession":"sales","title":"What 'commit' means, for marketing","scenario":"A marketing manager asked why sales won't count their sourced deals as commit yet. They don't know the forecast vocabulary. Your draft assumes they do.","task":"Write a 2-3 sentence explanation of commit discipline for a marketing peer, no sales jargon.","tips":["Define commit by the bet, not the CRM stage.","Show the shared stake: inflated commit burns both teams' credibility.","Keep it collegial — they're an ally, not a student."],"focus":["audience","clarity"]},
    {"id":"audience-sales-mid-13","level":"mid","profession":"sales","title":"The no-shorthand onboarding note","scenario":"A new AE starts Monday. Your welcome note references 'the Tier-1 list', 'the Q3 play', and 'the usual Friday pipeline scrub' — shorthand that means nothing to them yet.","task":"Rewrite the note in 3-4 sentences that assume zero context.","tips":["Spell out every internal term or cut it.","Tell them the one thing to prepare for day one.","A newcomer reads for orientation, not nostalgia."],"focus":["audience","clarity"]},
    {"id":"audience-sales-mid-14","level":"mid","profession":"sales","title":"The partner enablement blurb","scenario":"A reseller partner will pitch your product without you in the room. Your draft one-pager is written like an internal battlecard, full of competitive trash-talk and internal codenames.","task":"Write a 3-sentence positioning blurb a partner rep could say verbatim to a customer.","tips":["Write words that can be spoken to a customer as-is.","Cut codenames and competitor attacks; state your strength positively.","Lead with the customer problem, not your product category."],"focus":["audience","clarity"]},
    {"id":"audience-sales-mid-15","level":"mid","profession":"sales","title":"The slip explained to finance","scenario":"Finance asked why the Delacroix deal moved out of the quarter. Your draft is a sales story — champion went quiet, procurement stalled. Finance cares about cash timing and whether the revenue is still real.","task":"Write a 2-3 sentence explanation in finance's terms.","tips":["Lead with what finance models: new expected close date and confidence.","Say whether the amount changed.","One line on why, without the sales soap opera."],"focus":["audience","precision"],"placeholder":"Delacroix moves to mid-Q4, same $340k value, confidence unchanged —"},
    {"id":"audience-sales-mid-16","level":"mid","profession":"sales","title":"The promises handoff to CS","scenario":"During the deal you agreed to a custom onboarding schedule and quarterly exec reviews. CS is inheriting the account and needs commitments, dates, and who agreed to what — not the negotiation story.","task":"Write a 3-4 sentence handoff that gives CS exactly what they need to deliver.","tips":["List commitments as facts: what, by when, agreed with whom.","Cut the negotiation history.","Flag the commitment most likely to bite if missed."],"focus":["audience","precision"]},
    {"id":"audience-sales-mid-17","level":"mid","profession":"sales","title":"Same news, two altitudes","scenario":"Pipeline generation is up 30% but conversion from stage 2 to 3 dropped. Your CRO needs the one-line takeaway; your RevOps partner needs the specifics. You keep writing one message that serves neither.","task":"Write the one-sentence CRO version, then the 2-sentence RevOps version.","tips":["CRO altitude: net effect on the number and your call.","RevOps altitude: which stage, which segment, what to pull.","Never send the same altitude to both."],"focus":["audience","structure"]},
    {"id":"audience-sales-mid-18","level":"mid","profession":"sales","title":"Release notes into customer benefit","scenario":"Product shipped 'granular role-based access controls with audit logging.' You're drafting the customer-facing note for your accounts. Your current draft copies the release notes verbatim.","task":"Rewrite the announcement in 2-3 sentences of customer benefit.","tips":["Lead with what the customer can now do or stop worrying about.","Translate the feature into their compliance or security stake.","Offer the next step: a 15-minute walkthrough."],"focus":["audience","clarity"],"placeholder":"You can now control exactly who sees what — and prove it to your auditors."},
    {"id":"audience-sales-mid-19","level":"mid","profession":"sales","title":"The exec-sponsor briefing","scenario":"Your SVP agreed to host a dinner with five customer executives. Your prep note is a logistics dump — venue, timing, dietary notes. What the SVP needs: who's coming, what each cares about, and the one message to land.","task":"Write a 3-4 sentence briefing focused on what the SVP must know and do.","tips":["Lead with the one message the dinner should land.","One line per guest: name, role, what they care about.","Logistics go in a calendar invite, not the briefing."],"focus":["audience","structure"]},
    {"id":"audience-sales-mid-20","level":"mid","profession":"sales","title":"The legal handoff","scenario":"You're sending a contract to your legal team for review before a quarter-end signature. Your draft tells the whole deal story. Legal needs: what's non-standard, what the customer pushed on, and the date it must be back.","task":"Write a 3-sentence handoff note in legal's terms.","tips":["Lead with the deadline and why it's real.","List only the non-standard terms — that's what legal reads for.","Cut everything about how hard the deal was."],"focus":["audience","concision"],"placeholder":"Need this back by the 26th for a quarter-end signature. Two non-standard terms:"},
    {"id":"audience-sales-mid-21","level":"mid","profession":"sales","title":"The quota conversation, from their side","scenario":"You're telling a rep their quota rises 15% next year. Your draft justifies it from the company's view — growth targets, market opportunity. The rep will hear one thing: is this achievable and what changes for me?","task":"Write the 3-4 sentence opening of that conversation, framed around the rep's stake.","tips":["Name the number plainly, then answer their real question: how it's achievable.","Point to what they get: territory, leads, support.","Company strategy is context, not the argument."],"focus":["audience","clarity"]},
    {"id":"audience-sales-mid-22","level":"mid","profession":"sales","title":"The all-hands slide for non-sales","scenario":"You're presenting the quarter's biggest win at the company all-hands. Your draft uses ACV, multi-thread, and POC — vocabulary half the company doesn't share. Engineers and support staff are in the room.","task":"Write a 2-3 sentence version of the win story anyone in the company can follow.","tips":["Say what the customer's problem was and what we did, in plain words.","Give the size in terms everyone gets: our biggest deal this year.","Credit the non-sales teams who touched it."],"focus":["audience","clarity"]},
    {"id":"audience-sales-mid-23","level":"mid","profession":"sales","title":"The lead-scoring change for AEs","scenario":"You're changing lead routing so high-intent product signups skip the SDR queue and go straight to AEs. Your draft explains the scoring model mechanics. AEs need: what shows up in my name, when, and what do I do differently?","task":"Write a 3-sentence explanation pitched at the AE's workflow.","tips":["Lead with what changes in their queue Monday morning.","One line on why — speed to hot leads.","Say exactly what the new first step is."],"focus":["audience","clarity"]},
    {"id":"audience-sales-mid-24","level":"mid","profession":"sales","title":"One launch email, one audience","scenario":"Your launch email draft tries to speak to existing customers and cold prospects at once — and lands with neither. Existing customers want what's new for them; prospects need the problem framed from scratch.","task":"Choose the primary audience and write a 3-sentence launch email for them alone.","tips":["Pick one reader; let the other get their own email later.","For customers: lead with what improves in their current use.","Every sentence should assume the same starting knowledge."],"focus":["audience","structure"]},
    {"id":"audience-sales-mid-25","level":"mid","profession":"sales","title":"The analyst briefing paragraph","scenario":"An industry analyst asked for a written summary of your product's direction for their market report. Your draft is internal roadmap language — sprint names, initiative codenames, quarter numbers that mean nothing outside.","task":"Write a 3-sentence summary an outside analyst can quote accurately.","tips":["Write for someone who will paraphrase you to strangers — no internal names.","Anchor to market problems, not your org's initiatives.","Only claim dates you'd be comfortable seeing in print."],"focus":["audience","precision"]}
  ],
  "structure-that-carries": [
    {"id":"structure-sales-mid-01","level":"mid","profession":"sales","title":"The QBR governing idea","scenario":"Your quarterly business review deck is 30 slides of everything that happened. Leadership will remember one idea if you give them one. The quarter's real story: we traded volume for quality and win rate proved it out.","task":"Write the governing idea in one sentence, then name the three buckets of evidence beneath it.","tips":["One sentence at the top that the whole deck defends.","Three buckets maximum — merge or cut the rest.","Every slide should answer to one bucket."],"focus":["structure","clarity"],"placeholder":"We traded volume for quality this quarter, and win rate proved it out: "},
    {"id":"structure-sales-mid-02","level":"mid","profession":"sales","title":"SCQA for the headcount ask","scenario":"You're writing a one-pager asking for two more AEs. You have the data but no frame. Use SCQA: the Situation everyone agrees on, the Complication that changed, the Question it raises, your Answer.","task":"Write one sentence for each SCQA element of the headcount case.","tips":["Situation: uncontroversial — current team and coverage.","Complication: what changed — pipeline grew 40%, capacity didn't.","The Answer is your ask, stated as the resolution."],"focus":["structure","impact"]},
    {"id":"structure-sales-mid-03","level":"mid","profession":"sales","title":"PREP for 'why did we miss?'","scenario":"On tomorrow's leadership call you'll be asked why the team finished at 87%. You know the answer — two slipped enterprise deals — but under questioning you tend to ramble. PREP: Point, Reason, Example, Point.","task":"Write your spoken PREP answer in 4 sentences.","tips":["Point first: we missed because two enterprise deals slipped, not a pipeline problem.","Reason and example make it concrete — name the deals' pattern.","Restate the point with the forward action."],"focus":["structure","clarity"],"placeholder":"We finished at 87% because two enterprise deals slipped into Q4 —"},
    {"id":"structure-sales-mid-04","level":"mid","profession":"sales","title":"Twelve churn reasons, three themes","scenario":"Your churn post-mortems list twelve distinct reasons accounts left: no exec sponsor, poor onboarding, unused seats, price sensitivity, champion departed, missing feature, bad support experience, and more. Leadership can't act on twelve.","task":"Group the reasons into three named themes and write one sentence introducing them.","tips":["Group by root cause, not by symptom.","Name each theme so it suggests the fix.","Test: does every reason clearly belong to one theme?"],"focus":["structure","clarity"]},
    {"id":"structure-sales-mid-05","level":"mid","profession":"sales","title":"The forecast call skeleton","scenario":"Your segment of the forecast call keeps running long and scattered. You want a repeatable structure: the number, what moved, the risks, and what you need. Right now you improvise and bury your asks.","task":"Write the 4-line skeleton you'll use every week, one line per section.","tips":["Fixed order builds trust: number, movement, risk, ask.","Each section gets one sentence before any detail.","Put the ask in the structure so you never forget it."],"focus":["structure","concision"]},
    {"id":"structure-sales-mid-06","level":"mid","profession":"sales","title":"The win/loss report buckets","scenario":"You interviewed buyers from 15 wins and 15 losses. Your notes are chronological by interview. The report needs to carry a reader through: what wins us deals, what loses them, and what to change.","task":"Write the report's three section headers and the one-line finding under each.","tips":["Organize by finding, never by interview order.","Headers should assert something, not just label a topic.","The 'what to change' section is why anyone reads it."],"focus":["structure","impact"]},
    {"id":"structure-sales-mid-07","level":"mid","profession":"sales","title":"The campaign readout frame","scenario":"Your quarterly campaign readout mixes results, anecdotes, and plans in no order. Build it around one governing claim — the channel mix shifted and efficiency improved — with results, learnings, and next-quarter plan beneath.","task":"Write the governing claim and the three section headers as full sentences.","tips":["The claim up top tells them how to read everything after.","Make headers conclusions: 'Paid search outperformed events 3:1', not 'Channel results'.","Plans belong in the last bucket, grounded in the learnings."],"focus":["structure","clarity"]},
    {"id":"structure-sales-mid-08","level":"mid","profession":"sales","title":"The big-pursuit strategy doc","scenario":"You're writing the pursuit plan for a $500k opportunity with a strategic logo. Your draft is a pile of notes: stakeholders, competitors, timeline, risks. It needs one governing idea — why we win — with everything organized to support it.","task":"Write the 'why we win' sentence and the three buckets your plan hangs from.","tips":["The win thesis comes first; tactics serve it.","Buckets like: our wedge, their decision process, our risks.","If a note doesn't support the thesis, it's trivia."],"focus":["structure","impact"],"placeholder":"We win because we're the only option that works with their existing fleet —"},
    {"id":"structure-sales-mid-09","level":"mid","profession":"sales","title":"The coaching 1:1 agenda","scenario":"Your 1:1s with a struggling rep wander — a bit of deal talk, a bit of pep talk, no throughline. You want a fixed structure: the one skill in focus, evidence from this week's calls, one drill for next week.","task":"Write the 3-part agenda as three headers with one sentence each.","tips":["One skill per session — resist covering everything.","Evidence means specific moments from real calls.","End with one measurable action, not general encouragement."],"focus":["structure","clarity"]},
    {"id":"structure-sales-mid-10","level":"mid","profession":"sales","title":"Field asks in three buckets","scenario":"You collected feature requests from every rep before the product sync: nine asks ranging from a Salesforce integration fix to better pricing tiers. Presented as a list of nine, product will pick none.","task":"Group the nine asks into three buckets and write the one-sentence pitch for each bucket.","tips":["Group by the deal problem they solve, not by product area.","Rank the buckets — say which one moves the most revenue.","Three prioritized asks get action; nine get sympathy."],"focus":["structure","impact"]},
    {"id":"structure-sales-mid-11","level":"mid","profession":"sales","title":"The territory plan pyramid","scenario":"Your annual territory plan draft is a data dump: account lists, TAM figures, last year's numbers. The reader — your VP — needs one governing bet and the plan beneath it.","task":"Write the governing bet in one sentence, then the three plan sections that support it.","tips":["A plan is an argument: here is where the number comes from.","Sections might be: expand the base, crack the whitespace, defend the at-risk.","Data belongs under a section or in an appendix."],"focus":["structure","clarity"]},
    {"id":"structure-sales-mid-12","level":"mid","profession":"sales","title":"SCQA for the budget shift","scenario":"You want to move $80k from the fall trade show to paid search. Trade shows are tradition; the CMO is attached. Frame the case with SCQA rather than opening with the attack on events.","task":"Write the four SCQA sentences for the reallocation case.","tips":["Situation: the shared goal — pipeline per dollar.","Complication: what the data now shows about each channel.","Let the Question make the decision feel inevitable, then Answer it."],"focus":["structure","impact"]},
    {"id":"structure-sales-mid-13","level":"mid","profession":"sales","title":"The escalation email in three moves","scenario":"A strategic account's rollout is stalled and you're escalating to your SVP. Your draft is a wall of history. Structure it: situation in one line, business impact in one line, the specific ask with a date.","task":"Write the 3-sentence escalation using that structure.","tips":["One sentence each: what's happening, what it costs, what you need.","The ask names a person, an action, and a date.","History goes below a line break, for the curious."],"focus":["structure","concision"],"placeholder":"Rollout at Kessler has been stalled 3 weeks. At risk: the $280k renewal in March. Ask:"},
    {"id":"structure-sales-mid-14","level":"mid","profession":"sales","title":"The enablement session outline","scenario":"You're running a 45-minute session on negotiating against the new competitor. Your material is a heap: pricing intel, objection scripts, two war stories, a discounting policy reminder. Without structure, it becomes storytime.","task":"Write the session's one governing takeaway and its three sections.","tips":["One takeaway they should repeat in deals next week.","Three sections, each ending in something usable — a phrase, a play.","War stories are illustrations inside sections, not sections."],"focus":["structure","clarity"]},
    {"id":"structure-sales-mid-15","level":"mid","profession":"sales","title":"PREP for the upmarket question","scenario":"In the pipeline council, someone will ask whether your segment should push upmarket next year. You have a view: yes, but only in two verticals where you have proof. Unstructured, your answer will sprawl.","task":"Write the spoken PREP answer in 4 sentences.","tips":["Point: yes, narrowly — two verticals with proof.","One example carries more than three generalities.","The closing restatement is what they'll remember."],"focus":["structure","clarity"]},
    {"id":"structure-sales-mid-16","level":"mid","profession":"sales","title":"The pipeline-review grouping","scenario":"Your pipeline review doc lists 23 deals in CRM order. Your VP has 20 minutes. The deals actually sort into three stories: closing this month, stuck and needing help, and early but promising.","task":"Write the three group headers and the one-line summary for each group.","tips":["Group by what you want done, not by stage name.","Lead each group with its total value.","The 'needs help' group is where the meeting earns its time."],"focus":["structure","concision"]},
    {"id":"structure-sales-mid-17","level":"mid","profession":"sales","title":"The board-slide storyline","scenario":"The CMO asked you for one slide on marketing-sourced pipeline for the board. Your draft has six charts and no sentence. A board slide needs a headline that asserts, with charts as evidence.","task":"Write the slide's headline sentence and the two supporting points beneath it.","tips":["The headline is a claim: sourced pipeline doubled while cost held flat.","Two supporting points, each tied to one chart.","If a chart doesn't support the headline, cut it."],"focus":["structure","impact"],"placeholder":"Marketing-sourced pipeline doubled year over year at flat spend."},
    {"id":"structure-sales-mid-18","level":"mid","profession":"sales","title":"The kickoff talk spine","scenario":"You're giving the H2 kickoff talk to your team. You have twenty things to say: new comp plan, new territories, the competitive threat, last half's lessons. A talk with twenty points has none.","task":"Write the one-sentence theme of the talk and the three sections that carry it.","tips":["Pick the theme first; let it evict what doesn't fit.","Three sections your team can recall unprompted next week.","Announcements that don't fit the theme go in a follow-up email."],"focus":["structure","clarity"]},
    {"id":"structure-sales-mid-19","level":"mid","profession":"sales","title":"The renewal save plan","scenario":"A $200k account is wobbling and you're writing the save plan for your VP and the CS lead. Your notes cover relationship history, usage decline, a competitor's approach, and open support tickets — in no order.","task":"Structure the plan: write the one-line objective and the three workstreams under it.","tips":["Objective first: what saved looks like and by when.","Workstreams by lever: relationship, value proof, commercial terms.","Each workstream gets an owner in one word."],"focus":["structure","clarity"]},
    {"id":"structure-sales-mid-20","level":"mid","profession":"sales","title":"Nine requests, three asks","scenario":"Sales sent marketing nine requests this month: more case studies, better one-pagers, faster lead follow-up alerts, competitive cards, webinar topics, and more. You're the marketing manager consolidating them for your team's planning.","task":"Group the nine into three prioritized asks and write the sentence you'd send back to sales confirming them.","tips":["Group by sales outcome served: win deals, start conversations, defend against competitors.","Order by revenue impact, and say so.","Confirming the grouping back builds trust in the process."],"focus":["structure","audience"]},
    {"id":"structure-sales-mid-21","level":"mid","profession":"sales","title":"The launch comms plan","scenario":"You own field comms for next month's product launch: sales needs training, customers need notice, prospects need a campaign. Your plan draft is a chronological task list that hides the shape of the work.","task":"Write the plan's governing goal and the three audience-based workstreams beneath it.","tips":["Organize by audience, not by date — dates live inside each stream.","Each workstream: audience, message, moment.","The governing goal keeps the streams telling one story."],"focus":["structure","audience"]},
    {"id":"structure-sales-mid-22","level":"mid","profession":"sales","title":"The win story in three beats","scenario":"Marketing wants your Corvex win as a reference story. Your rep's writeup is a stream of meetings. Reference stories follow a spine: the situation they were stuck in, what changed with us, the measurable result.","task":"Write the three beats, one sentence each.","tips":["Beat one is the customer's pain, told from their side.","Beat two is the turn — what specifically changed.","Beat three needs a number a prospect would envy."],"focus":["structure","impact"]},
    {"id":"structure-sales-mid-23","level":"mid","profession":"sales","title":"SCQA for the new vertical","scenario":"You believe your team should formally enter healthcare — three inbound deals closed there without any focus. You're making the case to your CRO, who worries about compliance overhead and spread-thin reps.","task":"Write the four SCQA sentences for entering the vertical.","tips":["Situation: the accidental traction — three closed deals, zero investment.","Complication: unowned, the traction stalls or a competitor takes it.","Answer with a bounded first step, not a grand strategy."],"focus":["structure","impact"],"placeholder":"We closed three healthcare deals this year without trying."},
    {"id":"structure-sales-mid-24","level":"mid","profession":"sales","title":"The team email with three headers","scenario":"Your Friday team email covers a policy change, two shout-outs, a pipeline reminder, an event date, and a tooling tip in one unbroken block. Reps skim it and miss the policy change that actually matters.","task":"Restructure it: write three headers in priority order with one line of content each.","tips":["Header one carries the must-know; make it impossible to miss.","Group the nice-to-knows under one header.","If it fits no header, it doesn't belong this week."],"focus":["structure","concision"]},
    {"id":"structure-sales-mid-25","level":"mid","profession":"sales","title":"The battlecard skeleton","scenario":"Reps keep losing to the same competitor and your battlecard is a paragraph of prose they never read mid-call. It needs a fixed skeleton: their pitch, our counter, the proof point, the landmine question to plant.","task":"Write the four skeleton lines for one competitor using that structure.","tips":["Each line must be sayable on a live call.","The proof point is a fact, not an adjective.","The landmine is a question the competitor answers badly."],"focus":["structure","precision"]}
  ],
  "cut-to-the-bone": [
    {"id":"concise-sales-mid-01","level":"mid","profession":"sales","title":"The hedge-drenched commit","scenario":"Your forecast note reads: 'I feel like we could potentially be in a position to maybe land somewhere around the $1.5M mark, assuming things generally hold.' Your VP needs a number they can carry upward.","task":"Rewrite the commit line with the hedges cut and one honest condition kept.","tips":["One hedge maximum — pick the one that carries real information.","'I feel like', 'potentially', 'maybe', 'generally' can all go.","A condition is honest; a fog of qualifiers is not."],"focus":["concision","precision"],"placeholder":"Commit is $1.5M, assuming Halvorsen signs by the 20th."},
    {"id":"concise-sales-mid-02","level":"mid","profession":"sales","title":"The bloated CRM note","scenario":"Your rep's opportunity note runs 200 words of meeting play-by-play. The next reader — you, in Friday's pipeline scrub — needs four things: where the deal stands, what was agreed, what's blocking, next step with a date.","task":"Write the 4-line template note in under 40 words.","tips":["One line per fact; cut narration entirely.","Every line ends in something checkable.","If the next step has no date, it isn't a next step."],"focus":["concision","structure"]},
    {"id":"concise-sales-mid-03","level":"mid","profession":"sales","title":"The campaign summary, halved","scenario":"Your email campaign summary runs 300 words: open rates,段 by segment, subject-line tests, send-time notes. Your director will read the first three lines. The story: version B doubled replies, so you're rolling it out.","task":"Write the whole summary in 3 sentences.","tips":["Result, decision, next send — one sentence each.","Detail lives in the dashboard link, not the email.","If a sentence doesn't change what the reader does, cut it."],"focus":["concision","impact"],"placeholder":"Version B doubled reply rates (4.1% vs 2.0%)."},
    {"id":"concise-sales-mid-04","level":"mid","profession":"sales","title":"The throat-clearing QBR opener","scenario":"Your QBR script starts: 'Before I dive in, I just want to take a moment to thank everyone for making time, and I'll try to keep this brief, and please feel free to stop me with questions...' Forty seconds gone, nothing said.","task":"Write the opening two sentences with all the meta-commentary cut.","tips":["Start with the quarter's headline, not with logistics.","Meta-commentary ('I'll try to be brief') is never the message.","Respect for their time is shown by density, not announced."],"focus":["concision","impact"]},
    {"id":"concise-sales-mid-05","level":"mid","profession":"sales","title":"The redundant-pair proposal","scenario":"Your proposal draft is stuffed with pairs: 'goals and objectives', 'each and every account', 'full and complete visibility', 'basic and fundamental needs'. Each pair says one thing twice.","task":"Rewrite this sentence cutting every redundant pair: 'Our full and complete solution addresses each and every one of your goals and objectives for total and comprehensive pipeline visibility.'","tips":["Pick the stronger word of each pair; delete the other.","Doubled words read as padding, and buyers notice padding.","The lean version sounds more confident, not less."],"focus":["concision","clarity"]},
    {"id":"concise-sales-mid-06","level":"mid","profession":"sales","title":"The flabby coaching note","scenario":"Your written feedback to a rep reads: 'I think maybe you might want to consider possibly working on trying to do a bit more discovery before you kind of jump into the demo portion.' The message drowns.","task":"Rewrite the feedback in one direct, kind sentence.","tips":["'Consider possibly trying' is three hedges doing zero work.","Direct is kinder than vague — vague can't be acted on.","Name the specific behavior and the specific change."],"focus":["concision","clarity"],"placeholder":"Run discovery for ten minutes before you open the demo —"},
    {"id":"concise-sales-mid-07","level":"mid","profession":"sales","title":"The outbound sequence trim","scenario":"Your team's first outbound email runs 130 words with two paragraphs of company background before the point. Cold readers give it three seconds on a phone screen.","task":"Rewrite the email in under 50 words: reason for writing, relevance to them, one clear ask.","tips":["Cut all company background — nobody cold reads it.","One ask, sized small: 15 minutes, or even just a reply.","Read it on a phone screen in your head before sending."],"focus":["concision","audience"]},
    {"id":"concise-sales-mid-08","level":"mid","profession":"sales","title":"The six-paragraph escalation","scenario":"Your escalation email about a stalled implementation runs six paragraphs, mostly documenting that you tried everything before escalating. The SVP reading it needs three sentences.","task":"Cut the escalation to 3 sentences without losing the ask or the stakes.","tips":["Self-justification paragraphs protect you, not the account — cut them.","Keep: what's stuck, what it costs, what you need by when.","Attach the history; don't narrate it."],"focus":["concision","impact"]},
    {"id":"concise-sales-mid-09","level":"mid","profession":"sales","title":"The nominalization purge","scenario":"Your strategy doc reads: 'The implementation of the segmentation of accounts will result in the improvement of the utilization of rep capacity.' Nouns doing verb work, everywhere.","task":"Rewrite the sentence with verbs doing the work, in under 15 words.","tips":["Find the buried verbs: implement, segment, improve, use.","'The implementation of X' is always 'implementing X' or just 'X'.","Shorter sentence, clearer claim, easier to challenge — which is good."],"focus":["concision","clarity"],"placeholder":"Segmenting accounts lets reps spend time where it pays."},
    {"id":"concise-sales-mid-10","level":"mid","profession":"sales","title":"The voicemail script cut","scenario":"Your team's voicemail script runs 90 seconds — company intro, feature list, two calls to action. Prospects delete voicemails at the seven-second mark unless something lands.","task":"Write a voicemail script of 30 words or fewer: who, why relevant, one action.","tips":["Your name and one reason this matters to them — that's the intro.","One call to action, and make it the email you're about to send.","Practice it aloud; cut what trips your tongue."],"focus":["concision","impact"]},
    {"id":"concise-sales-mid-11","level":"mid","profession":"sales","title":"The 100-word exec summary","scenario":"Your 12-page annual marketing plan needs an executive summary. Your draft summary is a page. The CEO will read 100 words, and those 100 words decide whether the other 12 pages get a chance.","task":"Write the summary in under 100 words: the bet, the number, the top three moves.","tips":["Lead with the single bet the plan makes.","Numbers over adjectives: target pipeline, budget, expected return.","If a sentence survives without changing the decision, cut it."],"focus":["concision","structure"]},
    {"id":"concise-sales-mid-12","level":"mid","profession":"sales","title":"The renewal email warm-up","scenario":"Your renewal email opens: 'I hope this email finds you well. I know things have been incredibly busy on your end, and I really appreciate all the time you've given us this year...' The renewal ask arrives in paragraph three.","task":"Rewrite the email in 3 sentences with the warm-up cut to one clause at most.","tips":["One warm clause, then business: your renewal is due March 1.","Gratitude lands better attached to something specific.","Three paragraphs of throat-clearing signals discomfort with the ask."],"focus":["concision","clarity"]},
    {"id":"concise-sales-mid-13","level":"mid","profession":"sales","title":"The 60-word slide","scenario":"Your pipeline-council slide has 60 words: full sentences, sub-bullets, a caveat footnote. Slides are read in four seconds while you talk. The point: enterprise pipeline is up 40% but mid-market is thinning.","task":"Rewrite the slide as a headline and two bullets, 15 words total.","tips":["The headline states the tension: enterprise up, mid-market thinning.","Bullets are numbers, not sentences.","You are the caveats — speak them, don't print them."],"focus":["concision","structure"],"placeholder":"Enterprise up 40%; mid-market pipeline thinning"},
    {"id":"concise-sales-mid-14","level":"mid","profession":"sales","title":"The post-demo follow-up","scenario":"Your rep's follow-up email after a strong demo runs 250 words recapping every feature shown. The buyer needs three things: what was agreed, what happens next, what you need from them.","task":"Write the follow-up in 4 sentences.","tips":["Recap decisions and reactions, not the feature tour.","The next step gets a date and an owner.","Long follow-ups get filed; short ones get answered."],"focus":["concision","structure"]},
    {"id":"concise-sales-mid-15","level":"mid","profession":"sales","title":"The job-posting trim","scenario":"Your AE job posting runs 600 words — twelve responsibilities, nine requirements, three paragraphs of culture copy. Strong candidates skim; the posting reads like every other one.","task":"Write the three-sentence core of the posting: the job in one line, the one thing that makes it different, who thrives in it.","tips":["Cut requirements that every posting lists — they filter nobody.","The differentiator is why someone leaves a good job for this one.","Specific beats aspirational: quota, territory, tools, team size."],"focus":["concision","audience"]},
    {"id":"concise-sales-mid-16","level":"mid","profession":"sales","title":"The apologetic cross-team ask","scenario":"Your request to the design team reads: 'Sorry to bother you, I know you're all slammed, and this is probably a big ask, and totally fine if not, but is there any chance someone could maybe look at the one-pager?' The ask is invisible under the apology.","task":"Rewrite the request in 2 sentences: the ask with a date, and one line of context.","tips":["Cut every pre-apology; keep one 'thanks' at most.","Name the deliverable and the date.","Over-apologizing makes work easy to deprioritize."],"focus":["concision","clarity"],"placeholder":"Could design review the launch one-pager by Wednesday?"},
    {"id":"concise-sales-mid-17","level":"mid","profession":"sales","title":"The meeting-invite description","scenario":"Your invite for the pipeline scrub has a description nobody reads: four paragraphs of background and a link dump. Attendees show up unprepared anyway. The description should be three lines: purpose, what to prep, what we'll decide.","task":"Write the 3-line invite description.","tips":["Purpose in line one — what this meeting is for.","'Come with' is one specific item, not 'review the docs'.","Name the decision the meeting must produce."],"focus":["concision","structure"]},
    {"id":"concise-sales-mid-18","level":"mid","profession":"sales","title":"The win-story writeup, halved","scenario":"Your case-study draft for marketing runs 800 words with the customer's quote buried in paragraph six. Marketing asked for 400 words and prospects will read 150.","task":"Write the 3-sentence version that would survive any further cut: problem, solution, quantified result.","tips":["Find the sentence with the number — everything orbits it.","The customer quote earns its place near the top.","Halving twice teaches you what was structural and what was filler."],"focus":["concision","impact"]},
    {"id":"concise-sales-mid-19","level":"mid","profession":"sales","title":"The Friday team email diet","scenario":"Your weekly team email has grown to 500 words and open rates inside your own team are dropping. This week's essentials: the deal-desk cutoff moved to Thursday, and pipeline entries close Friday noon.","task":"Write the entire email in under 40 words.","tips":["Two facts, two lines, done.","Recognition and color can be a separate, optional note.","An email everyone reads beats a newsletter everyone skips."],"focus":["concision","clarity"],"placeholder":"Two deadlines this week: deal desk moves to Thursday; pipeline closes Friday noon."},
    {"id":"concise-sales-mid-20","level":"mid","profession":"sales","title":"The battlecard bullet","scenario":"A battlecard line reads: 'It is worth noting that in many cases customers have generally found that our onboarding process tends to be significantly more streamlined and efficient in comparison with the competition.' A rep can't say that on a call.","task":"Rewrite the bullet in under 12 words, sayable aloud.","tips":["Cut 'it is worth noting', 'in many cases', 'generally', 'tends to'.","A claim with a number survives contact with a skeptic.","Test: can you say it naturally mid-conversation?"],"focus":["concision","precision"],"placeholder":"Our customers onboard in 2 weeks; theirs average 6."},
    {"id":"concise-sales-mid-21","level":"mid","profession":"sales","title":"The pricing-defense hedge cut","scenario":"Asked to justify your price, your draft says: 'We believe that our pricing is, in most respects, quite competitive when you sort of factor in the overall long-term value.' Every hedge invites the buyer to push.","task":"Rewrite the pricing defense in 1-2 hedge-free sentences.","tips":["'We believe', 'in most respects', 'sort of' — all invitations to argue.","Anchor to a cost the buyer already pays.","State it like a fact you can defend, because you can."],"focus":["concision","impact"]},
    {"id":"concise-sales-mid-22","level":"mid","profession":"sales","title":"The deal-review notes cut","scenario":"Your notes from today's deal review run a full page per deal. The reps need to leave with one thing each: what was decided about their deal and what they owe by when.","task":"Write the one-line-per-deal format and fill it in for one example deal.","tips":["Format: deal, decision, owner, date. Nothing else.","Discussion is remembered; only decisions need recording.","If a line has no owner and date, it decided nothing."],"focus":["concision","structure"]},
    {"id":"concise-sales-mid-23","level":"mid","profession":"sales","title":"The launch-update compression","scenario":"Your weekly launch update to stakeholders lists every task across sales training, campaign prep, and customer comms. Twelve stakeholders skim for one thing: on track or not, and where the risk is.","task":"Write the update in 2 sentences: overall status, and the single item at risk.","tips":["Green or amber in the first three words.","One risk named beats ten tasks listed.","Whoever needs task detail is in your project tracker already."],"focus":["concision","impact"],"placeholder":"Launch is on track for the 14th. One risk:"},
    {"id":"concise-sales-mid-24","level":"mid","profession":"sales","title":"The rambling thread reply","scenario":"A long Slack thread is debating whether to extend a promotion. Your draft reply recaps the whole thread before adding your view. Everyone in the thread already read the thread.","task":"Write your reply in 2 sentences: your position and your single strongest reason.","tips":["Never recap a thread to its own participants.","Position first, one reason, stop.","Brevity in threads is a gift everyone notices."],"focus":["concision","clarity"]},
    {"id":"concise-sales-mid-25","level":"mid","profession":"sales","title":"The double-length one-pager","scenario":"Your 'one-pager' for the new service tier has become two pages. Cutting means choosing: the buyer needs the problem, the offer, proof, and price. Everything else is your team talking to itself.","task":"List the four sections you'd keep and write the single sentence for the section you'd cut hardest.","tips":["A one-pager is defined by what it omits.","Internal enthusiasm ('we're excited to...') is always the first cut.","Proof is one customer number, not three paragraphs."],"focus":["concision","structure"]}
  ],
  "precision-and-evidence": [
    {"id":"precision-sales-mid-01","level":"mid","profession":"sales","title":"'Pipeline is strong' means what?","scenario":"Your forecast note tells the VP 'the pipeline looks strong and momentum is building.' The VP can't act on a mood. They need coverage, stage mix, and how much is new versus aged.","task":"Rewrite the line with numbers: coverage ratio, new pipeline this week, and one aged risk.","tips":["Replace 'strong' with the coverage ratio against target.","'Momentum' is a number: pipeline added this week versus last.","One vague adjective is worth less than one hard figure."],"focus":["precision","clarity"],"placeholder":"Coverage is 3.2x with $400k added this week; one $180k deal is now 60 days aged."},
    {"id":"precision-sales-mid-02","level":"mid","profession":"sales","title":"The 'soon' that means nothing","scenario":"You tell your CRO the Meridian deal 'should close soon' and the customer is 'very engaged.' Under questioning you can't defend either claim. The CRO needs a date and the evidence behind it.","task":"Rewrite the update with a specific close date and the concrete signal that supports it.","tips":["'Soon' becomes a date you'd bet on: signature by the 22nd.","'Engaged' becomes an action they took: legal is in redlines.","If you can't name the evidence, lower the confidence, not the specificity."],"focus":["precision","clarity"],"placeholder":"Meridian signs by the 22nd — their legal returned redlines Tuesday and we close them Friday."},
    {"id":"precision-sales-mid-03","level":"mid","profession":"sales","title":"So what, from the dashboard","scenario":"Your campaign dashboard shows open rate 38%, CTR 4.2%, MQLs 210, conversion to SQL 18%. You paste all four into the readout. Leadership needs the one insight the numbers add up to, not the numbers themselves.","task":"Write the single What / So What / Now What insight the data supports, in 3 sentences.","tips":["The What is the one number that moved most against benchmark.","The So What is what it means for pipeline or spend.","The Now What is the decision you're recommending because of it."],"focus":["precision","impact"]},
    {"id":"precision-sales-mid-04","level":"mid","profession":"sales","title":"The skeptic-test claim","scenario":"Your deal-review write-up says the Brightline opportunity is 'basically a done deal.' A skeptical VP will ask: signed? verbal? budget confirmed? sponsor still there? Your claim has to survive that.","task":"Rewrite the status so it passes the skeptic test: state exactly what's confirmed and what isn't.","tips":["Say what's signed, what's verbal, and what's still open.","'Basically done' invites exactly the question you can't answer.","Precision about what's unconfirmed is what earns trust."],"focus":["precision","clarity"]},
    {"id":"precision-sales-mid-05","level":"mid","profession":"sales","title":"'Better ROI' with no number","scenario":"Your case for shifting budget to paid search says it 'delivers much better ROI than events.' The CFO will want the ratio. You have it: $0.11 per pipeline dollar versus $0.34 for events.","task":"Rewrite the claim with the two figures and the comparison stated plainly.","tips":["'Much better' is a ratio: three times more efficient.","Give both numbers so the comparison is checkable.","One clean comparison beats a paragraph of superlatives."],"focus":["precision","impact"],"placeholder":"Paid search sources pipeline at $0.11 per dollar; events cost $0.34 — three times more efficient."},
    {"id":"precision-sales-mid-06","level":"mid","profession":"sales","title":"The vague coaching observation","scenario":"Your feedback to a rep is 'your discovery calls could be tighter.' The rep doesn't know what to change. You actually mean: they ask closed questions and talk 70% of the time.","task":"Rewrite the feedback with the specific, observable behavior and the target.","tips":["Name the behavior you can measure: talk time, question type.","Give a target: aim for a 40/60 talk ratio in their favor.","Vague feedback can't be practiced; specific feedback can."],"focus":["precision","clarity"]},
    {"id":"precision-sales-mid-07","level":"mid","profession":"sales","title":"The 'lots of interest' launch claim","scenario":"You tell leadership the launch got 'a lot of interest and great feedback.' They ask what that translates to. You have it: 340 demo requests, 22 opportunities, $900k early pipeline.","task":"Rewrite the launch summary replacing every vague term with a figure.","tips":["'A lot of interest' is demo requests, counted.","'Great feedback' is opportunities created, not sentiment.","End with the pipeline number — that's the point of interest."],"focus":["precision","impact"],"placeholder":"The launch drove 340 demo requests and 22 opportunities — $900k in early pipeline."},
    {"id":"precision-sales-mid-08","level":"mid","profession":"sales","title":"Data into one territory insight","scenario":"Your territory analysis has 30 rows: accounts by size, industry, last-touch date, spend. Your VP won't read the table. The pattern that matters: 60% of untapped revenue sits in eight logistics accounts nobody has called in 90 days.","task":"Write the one-sentence insight the table supports, with the numbers that anchor it.","tips":["Lead the reader to the one pattern, not the whole grid.","Anchor with the two numbers that make it undeniable.","The table is evidence; the sentence is the finding."],"focus":["precision","structure"],"placeholder":"60% of our untapped revenue sits in eight logistics accounts untouched for 90+ days."},
    {"id":"precision-sales-mid-09","level":"mid","profession":"sales","title":"The renewal risk, quantified","scenario":"You flag that an account is 'at some risk' at renewal. Your VP needs to size it. You know: usage is down 40%, the champion left, and it's a $250k renewal due in 60 days.","task":"Rewrite the flag with the three concrete signals and the dollar and time figures.","tips":["'Some risk' is a number: $250k due in 60 days.","Give the signals that make it risk: usage down 40%, champion gone.","Precision lets leadership decide how hard to fight for it."],"focus":["precision","impact"]},
    {"id":"precision-sales-mid-10","level":"mid","profession":"sales","title":"'Competitive' pricing, defended","scenario":"A prospect challenges your price. Your reflex answer — 'our pricing is very competitive' — invites a pushback. You can instead anchor to a number: they'll save the equivalent of 1.5 headcount in the first year.","task":"Write the price defense anchored to one quantified customer outcome.","tips":["Drop 'competitive' — it's a claim about you, not value to them.","Anchor to a cost they already carry: headcount, hours, churn.","One defensible number ends the price debate faster than adjectives."],"focus":["precision","impact"],"placeholder":"At current volumes this replaces roughly 1.5 headcount of manual work in year one."},
    {"id":"precision-sales-mid-11","level":"mid","profession":"sales","title":"The 'trending well' status","scenario":"Your weekly launch-readiness note says prep is 'trending well' and 'mostly on track.' Stakeholders can't plan against that. The truth: sales training is done, campaign assets are 80% built, customer comms haven't started.","task":"Rewrite the status with a concrete completion figure for each of the three workstreams.","tips":["Replace 'mostly' with a percentage or a done/not-done per stream.","Name the stream that's behind, plainly.","'Trending well' hides exactly the stream that needs attention."],"focus":["precision","clarity"]},
    {"id":"precision-sales-mid-12","level":"mid","profession":"sales","title":"The win rate, sourced","scenario":"You claim in the QBR that 'win rates improved a lot' after the new qualification process. A CFO wants the before and after. You have it: 18% to 27% over two quarters on 140 deals.","task":"Write the claim with the before, after, and sample size stated.","tips":["Two numbers and a denominator make a claim credible.","'A lot' hides whether it's noise or signal — the sample answers that.","Attach the timeframe so nobody assumes it's one lucky month."],"focus":["precision","impact"],"placeholder":"Win rate rose from 18% to 27% over two quarters across 140 deals."},
    {"id":"precision-sales-mid-13","level":"mid","profession":"sales","title":"The forecast confidence number","scenario":"Asked how confident you are in the quarter, you say 'pretty confident.' Your CRO wants a percentage and the swing factor. You'd put it at 80%, hinging on two deals worth $350k.","task":"Rewrite the answer with a confidence figure and the specific swing.","tips":["Give a number: 80%, not 'pretty confident'.","Name what would move it: which deals, what dollar swing.","A quantified confidence is one a CRO can carry to their boss."],"focus":["precision","clarity"]},
    {"id":"precision-sales-mid-14","level":"mid","profession":"sales","title":"The 'engagement is up' campaign line","scenario":"Your readout says nurture-email 'engagement is up.' Up from what, by how much, and does it convert? You have it: click-to-reply rose from 1.1% to 3.4%, and those replies convert to meetings at 2x the list average.","task":"Rewrite the line with the before/after and the conversion follow-through.","tips":["'Up' needs a baseline and a new value.","Tie the engagement metric to a downstream outcome — meetings, pipeline.","Engagement without conversion is vanity; state the link."],"focus":["precision","impact"]},
    {"id":"precision-sales-mid-15","level":"mid","profession":"sales","title":"The 'we've tried everything' escalation","scenario":"Your escalation says you've 'tried everything' to unstick the deal. Leadership hears an excuse, not evidence. You've actually done three specific things — name them and name the one lever left that needs their help.","task":"Rewrite the escalation listing the three attempts specifically and the one ask.","tips":["'Everything' proves nothing; three named actions prove diligence.","Each attempt is one clause: what you did, what happened.","End with the single lever only they can pull."],"focus":["precision","impact"]},
    {"id":"precision-sales-mid-16","level":"mid","profession":"sales","title":"The rep-ranking with no metric","scenario":"You tell your VP one rep is 'clearly your strongest.' The VP wants the basis. You mean: highest win rate, best deal hygiene, and consistent quarter-over-quarter attainment — not just the loudest in meetings.","task":"Write the assessment naming the three metrics that support 'strongest.'","tips":["'Clearly strongest' should rest on numbers, not charisma.","Pick metrics that predict future performance, not just last quarter.","Naming the basis protects you if the ranking is questioned."],"focus":["precision","clarity"]},
    {"id":"precision-sales-mid-17","level":"mid","profession":"sales","title":"The vague market-size claim","scenario":"Your case for the new vertical says the market is 'huge' and 'growing fast.' Your CRO wants a defensible number. You have a range: roughly 4,000 target accounts, ~$40M addressable at your ACV, growing ~15% a year.","task":"Rewrite the claim with the account count, dollar figure, and growth rate.","tips":["'Huge' is a number you can defend or a range you can bound.","State your assumptions so the number is checkable, not magic.","A conservative defensible figure beats an impressive unprovable one."],"focus":["precision","impact"],"placeholder":"~4,000 target accounts, roughly $40M addressable at our ACV, growing ~15% a year."},
    {"id":"precision-sales-mid-18","level":"mid","profession":"sales","title":"'Customers love it' — evidence?","scenario":"Your board input claims 'customers love the new tier.' The CMO asks for proof beyond a feeling. You have it: 92% of buyers who saw it added it, NPS on it is 61, and three renewals cited it.","task":"Rewrite the claim with three pieces of evidence, each a number.","tips":["'Love' is attach rate, NPS, and retention — measurable things.","Three specific proofs beat one enthusiastic adjective.","Cite the source of each number so it holds up on a board slide."],"focus":["precision","impact"]},
    {"id":"precision-sales-mid-19","level":"mid","profession":"sales","title":"The 'ramp is slow' problem","scenario":"You tell your VP a new hire's 'ramp is slow.' Slow against what? You mean: at month four they're at 30% of a fully-ramped rep's pipeline, where the average new hire is at 60%.","task":"Rewrite the concern with the benchmark and the gap quantified.","tips":["'Slow' needs a benchmark: the average ramp curve.","State where they are and where they should be, in the same unit.","The gap, quantified, tells you whether to coach or worry."],"focus":["precision","clarity"]},
    {"id":"precision-sales-mid-20","level":"mid","profession":"sales","title":"The discount impact, made real","scenario":"You're arguing against a blanket 15% discount policy. Saying it 'hurts margin' isn't enough. You've modeled it: on last quarter's volume, 15% off costs $340k in gross profit and moves breakeven out two months.","task":"Write the argument with the dollar cost and the timeline impact stated.","tips":["'Hurts margin' becomes a dollar figure on real volume.","Add the second-order effect: what it does to breakeven or payback.","Numbers turn a policy opinion into a business decision."],"focus":["precision","impact"],"placeholder":"On last quarter's volume, a 15% blanket discount costs $340k in gross profit."},
    {"id":"precision-sales-mid-21","level":"mid","profession":"sales","title":"The 'good quarter' summary","scenario":"Your quarter-close note to leadership calls it 'a good quarter with strong performance.' Leadership wants the scoreboard. You closed 104% of plan, win rate held at 26%, and average deal size rose 12%.","task":"Rewrite the summary as three metrics against their targets, no adjectives.","tips":["'Good' is attainment against plan, stated as a percentage.","Pick the three numbers that define the quarter's shape.","Let the reader conclude 'good' from the figures themselves."],"focus":["precision","structure"],"placeholder":"We closed at 104% of plan; win rate held at 26% and average deal size rose 12%."},
    {"id":"precision-sales-mid-22","level":"mid","profession":"sales","title":"The 'they went dark' claim","scenario":"You report a champion 'went dark.' Your VP asks when and after what. Precisely: they stopped replying 11 days ago, right after you sent pricing, and haven't opened the last two emails.","task":"Rewrite the status with the timing and the trigger stated specifically.","tips":["'Went dark' becomes a date and a last-known action.","The trigger — right after pricing — is the diagnostic detail.","Read receipts and timing turn a vague worry into a plan."],"focus":["precision","clarity"]},
    {"id":"precision-sales-mid-23","level":"mid","profession":"sales","title":"The 'most' that's really a third","scenario":"Your readout says 'most of our pipeline comes from marketing.' The CEO repeats it in a board meeting — and it's wrong. It's actually 38% marketing-sourced, 44% sales-sourced, the rest partner.","task":"Rewrite the line with the exact split so nobody misquotes it upward.","tips":["'Most' invites overclaiming — give the real percentages.","Show all three sources so the picture is complete.","A number that gets repeated to a board must be exactly right."],"focus":["precision","clarity"]},
    {"id":"precision-sales-mid-24","level":"mid","profession":"sales","title":"The forecast miss, diagnosed","scenario":"You finished at 91%. 'A few deals slipped' isn't a diagnosis. The real picture: two deals ($220k) slipped to Q4 on customer budget freezes, and one ($90k) was lost to a competitor on price.","task":"Write the miss explanation with each deal, its size, and its specific cause.","tips":["Separate slips (still real) from losses (gone) — they mean different things.","Attach a dollar figure and a cause to each.","A precise diagnosis is what lets you fix the right thing."],"focus":["precision","impact"]},
    {"id":"precision-sales-mid-25","level":"mid","profession":"sales","title":"The 'high-intent' lead definition","scenario":"You're asking to route 'high-intent' leads straight to AEs, but no one agrees what high-intent means. You need a precise, testable definition: two+ pricing-page visits and a demo request within seven days.","task":"Write the one-sentence operational definition of a high-intent lead, with thresholds.","tips":["A useful definition is testable by a system, not a vibe.","Name the exact signals and the exact thresholds.","If two people can't apply it identically, it's not precise enough."],"focus":["precision","clarity"],"placeholder":"High-intent: two or more pricing-page views plus a demo request within seven days."}
  ],
  "executive-presence": [
    {"id":"presence-sales-mid-01","level":"mid","profession":"sales","title":"The menu with no recommendation","scenario":"You lay out three options for the mid-market comp plan to your CRO — current, accelerator, and a hybrid — with pros and cons for each, then stop. The CRO wants to know which one you'd pick and why.","task":"Rewrite the close so you own a recommendation, then give the one reason.","tips":["A menu with no pick pushes your job onto the CRO.","State your choice, then the single reason it wins.","Owning the call is what separates a manager from a note-taker."],"focus":["impact","clarity"],"placeholder":"I'd move to the accelerator model — it rewards the behavior we actually need next quarter."},
    {"id":"presence-sales-mid-02","level":"mid","profession":"sales","title":"Fact versus your read","scenario":"In the forecast call you say 'the deal is going great and they'll definitely sign.' Half of that is fact, half is your read. Leadership needs to know which is which — the CFO plans differently on a fact than on a hunch.","task":"Rewrite the update separating what's confirmed from what's your judgment.","tips":["Label it: 'confirmed' versus 'my read is'.","Facts are things the customer did; reads are your interpretation.","Mixing them costs you credibility when a 'definite' slips."],"focus":["precision","clarity"],"placeholder":"Confirmed: legal is in redlines. My read: they sign this quarter, ~80%."},
    {"id":"presence-sales-mid-03","level":"mid","profession":"sales","title":"Signpost the forecast call","scenario":"Your part of the forecast call is a stream of deals with no map. Leadership loses the thread. Give them a signpost: three things — the number, the two risks, the one ask — then walk each.","task":"Write the two-sentence signpost that opens your segment.","tips":["Tell them the shape before the detail: 'Three things.'","Signposting lets a busy listener track where you are.","It also forces you to know your own structure."],"focus":["structure","impact"],"placeholder":"Three things: the number's holding, two deals carry risk, and I need one exec call."},
    {"id":"presence-sales-mid-04","level":"mid","profession":"sales","title":"The apology that undercuts you","scenario":"You open your campaign readout with 'sorry, I know this isn't perfect and I ran out of time on the analysis.' Leadership now doubts the whole thing. The work is solid; your framing is sabotaging it.","task":"Rewrite the opening to present the work with authority, keeping any real caveat as a single confident line.","tips":["Don't pre-apologize for work you're about to defend.","A genuine limitation is stated once, plainly, not as an apology.","Presence is treating your own work as worth their attention."],"focus":["impact","clarity"]},
    {"id":"presence-sales-mid-05","level":"mid","profession":"sales","title":"Own the budget call","scenario":"The CMO asks where to put the incremental $100k. You say 'well, it could go to events, or search, or content, they all have merit...' and trail off. You actually believe it should go to search. Say so.","task":"Write the recommendation, owned, with the one reason and the tradeoff you accept.","tips":["Pick one and defend it; 'they all have merit' is a non-answer.","Name what you're giving up — that shows you weighed it.","Executives fund conviction, not even-handedness."],"focus":["impact","clarity"],"placeholder":"Put it in paid search. We give up some event presence, but search returns three times the pipeline per dollar."},
    {"id":"presence-sales-mid-06","level":"mid","profession":"sales","title":"The rep who wants you to decide","scenario":"A rep asks whether to walk away from a stalled deal or keep investing. You could reflect it back — but presence is giving a clear steer. Your read: walk, because there's no budget and no sponsor.","task":"Write the 2-3 sentence steer that owns a recommendation while leaving the rep the call.","tips":["Give your recommendation clearly, then hand them the decision.","'I'd walk, and here's why' beats 'well, what do you think?'","Coaching with a spine builds reps who make calls."],"focus":["impact","clarity"]},
    {"id":"presence-sales-mid-07","level":"mid","profession":"sales","title":"The board-slide voice","scenario":"Your marketing slide for the board reads like an internal update: 'we've been working hard on a number of initiatives.' A board expects a claim and a number. Rewrite it to assert something and stand behind it.","task":"Write the slide's headline in an executive register: one assertion, one number.","tips":["Boards read assertions, not activity logs.","'Working hard on initiatives' says nothing you'd defend.","State the result as if you'll be asked to prove it — because you will."],"focus":["impact","clarity"],"placeholder":"Marketing sourced 44% of closed revenue this year, up from 31%."},
    {"id":"presence-sales-mid-08","level":"mid","profession":"sales","title":"Holding the room on a hard number","scenario":"You're presenting a forecast that's below plan. Your instinct is to rush past it, apologize, and over-explain. Presence is naming the number calmly, owning the cause, and stating the plan — without flinching.","task":"Write the 3-sentence delivery: the number, the cause you own, the plan.","tips":["Say the number without softening or speeding up.","Own the cause without blaming the team or the market.","End on the plan — that's what steadies the room."],"focus":["impact","clarity"]},
    {"id":"presence-sales-mid-09","level":"mid","profession":"sales","title":"The recommendation buried in analysis","scenario":"Your territory-realignment proposal spends two pages on analysis before a tentative 'we might consider' rebalancing. Your VP wants your recommendation up front, stated as a recommendation, with the analysis as support.","task":"Write the opening that leads with a clear recommendation, not 'we might consider.'","tips":["'I recommend' outranks 'we might consider' every time.","Lead with the call; the analysis is why, not whether.","Tentative language reads as you not trusting your own work."],"focus":["impact","structure"],"placeholder":"I recommend moving three enterprise accounts from the East to the Central territory this quarter."},
    {"id":"presence-sales-mid-10","level":"mid","profession":"sales","title":"The judgment call, labeled","scenario":"You're advising leadership to pass on a big but bad-fit deal. Facts: no budget, wrong segment. Judgment: chasing it burns two months better spent elsewhere. Separate the two so they can weigh your judgment for what it is.","task":"Write the 3-sentence case, labeling what's fact and what's your judgment.","tips":["Facts first, plainly stated and verifiable.","Then 'my judgment is' — own it as yours.","Leaders trust advisors who don't dress opinion as fact."],"focus":["precision","impact"]},
    {"id":"presence-sales-mid-11","level":"mid","profession":"sales","title":"The all-hands stage","scenario":"You're presenting the quarter at the all-hands and your notes are a hedge-fest: 'we sort of hit most of our goals, more or less.' The room reads uncertainty. Own the result — good or mixed — with a clear voice.","task":"Rewrite the two opening sentences with the hedges gone and the result owned.","tips":["'Sort of, more or less' broadcasts insecurity.","State the result plainly; the room can handle a real number.","Presence on stage is calm certainty about what happened."],"focus":["impact","concision"]},
    {"id":"presence-sales-mid-12","level":"mid","profession":"sales","title":"Signposting a long readout","scenario":"Your 40-minute campaign readout has no navigation. Leadership can't tell an important point from a minor one. Add signposts: 'The headline is X. Three reasons. Then what I need from you.'","task":"Write the signposting spine — the four transition lines that carry the readout.","tips":["Signposts tell the listener what kind of thing is coming.","'The one thing that matters here is...' earns attention.","A signposted talk feels controlled; presence is control."],"focus":["structure","impact"]},
    {"id":"presence-sales-mid-13","level":"mid","profession":"sales","title":"The deferential email to the CRO","scenario":"Your email to the CRO is all deference: 'whatever you think is best, I'm happy to go either way, just let me know.' You're the field expert here. The CRO wants your view, stated as a view.","task":"Rewrite the email to offer a clear recommendation while remaining respectful.","tips":["Respect and a spine coexist: 'My recommendation is X; happy to discuss.'","Endless deference makes you a scribe, not a partner.","Executives promote people who bring a view, not a blank check."],"focus":["impact","audience"]},
    {"id":"presence-sales-mid-14","level":"mid","profession":"sales","title":"Owning a miss without groveling","scenario":"Your team missed the quarter and you're addressing your VP. There's a line between owning it and self-flagellating. Own the miss, name what you'll change, and don't spend five sentences apologizing.","task":"Write the 3-sentence message: own the miss, the cause, the one change.","tips":["Own it in one clean sentence — no grovel, no excuse.","Name the specific change, not 'we'll try harder'.","Over-apologizing shifts the focus to your feelings, not the fix."],"focus":["impact","clarity"]},
    {"id":"presence-sales-mid-15","level":"mid","profession":"sales","title":"The recommendation to enter a vertical","scenario":"You believe the team should enter healthcare. Your draft to the CRO presents 'some considerations' neutrally. Presence means recommending it, owning the risk, and asking for a specific decision.","task":"Write the opening that states the recommendation and the decision you're asking for.","tips":["Recommend, don't 'raise for discussion'.","Name the risk yourself so it doesn't look like you missed it.","Ask for a specific yes/no, not general reactions."],"focus":["impact","clarity"],"placeholder":"I recommend we formally enter healthcare next quarter, starting with two verticals — here's the ask."},
    {"id":"presence-sales-mid-16","level":"mid","profession":"sales","title":"The confident 'here's what I'd do'","scenario":"Leadership is stuck between cutting the plan or investing in pipeline. Everyone's hedging. You have a view: invest, because the coverage gap is fixable in one quarter. Say it with conviction.","task":"Write the 2-3 sentence intervention that states your view and the reasoning cleanly.","tips":["In a room of hedgers, a clear view carries.","'Here's what I'd do and why' cuts through the stall.","Back conviction with one solid reason, not bravado."],"focus":["impact","clarity"]},
    {"id":"presence-sales-mid-17","level":"mid","profession":"sales","title":"The customer-exec meeting voice","scenario":"You're across the table from the customer's VP of Ops. Your draft talking points are tentative and eager-to-please. This exec respects a peer who states a clear point of view about their business, not a vendor angling for approval.","task":"Write the 2-3 sentence opening that establishes you as a peer with a point of view.","tips":["Lead with an insight about their business, not your product.","Speak as an equal advisor, not a supplicant.","Presence with a customer exec is earned by having a view worth hearing."],"focus":["impact","audience"]},
    {"id":"presence-sales-mid-18","level":"mid","profession":"sales","title":"The clean 'I recommend we don't'","scenario":"Product wants to bundle a feature into the launch that your field says will confuse the pitch. Recommending against a peer team's plan takes presence. State it clearly, own the reasoning, keep it collegial.","task":"Write the 2-3 sentence recommendation against the bundle, owned and respectful.","tips":["'I recommend we don't' is a valid, strong position.","Ground it in field evidence, not preference.","Disagreeing clearly and kindly is a presence skill."],"focus":["impact","clarity"]},
    {"id":"presence-sales-mid-19","level":"mid","profession":"sales","title":"The status update that projects control","scenario":"Your launch-readiness update reads anxious: 'I think we're okay but there's a lot up in the air.' Stakeholders mirror your anxiety. Even when things are tight, presence is stating status and risk with a steady hand.","task":"Rewrite the update to project control: clear status, one named risk, your plan for it.","tips":["Anxiety is contagious; so is calm.","Name the risk and the mitigation in the same breath.","'Here's the risk and here's what I'm doing' reads as in-command."],"focus":["impact","clarity"]},
    {"id":"presence-sales-mid-20","level":"mid","profession":"sales","title":"Separating the data from the spin","scenario":"Your win report mixes numbers with cheerleading: 'we crushed it, win rate is up, the team is on fire.' Leadership can't find the fact under the spin. State the facts flatly and let them speak.","task":"Rewrite the summary with the facts stated plainly and the hype removed.","tips":["Facts don't need adjectives to be impressive.","'On fire' hides whether the number is real or lucky.","Understatement over hard numbers reads as more senior."],"focus":["impact","precision"]},
    {"id":"presence-sales-mid-21","level":"mid","profession":"sales","title":"The recommendation under a tight ask","scenario":"Your CRO asks, in a hallway, 'headcount or tooling for next quarter — which?' You have thirty seconds. Presence is answering with a clear pick and one reason, not 'it depends on a lot of things.'","task":"Write the 2-sentence spoken answer: your pick and the one reason.","tips":["'It depends' is the answer of someone who hasn't decided.","Pick, then one reason — you can add nuance if asked.","Fast, clear answers in the hallway build your reputation."],"focus":["impact","concision"],"placeholder":"Headcount. Our coverage gap is a capacity problem, not a tooling one."},
    {"id":"presence-sales-mid-22","level":"mid","profession":"sales","title":"Standing behind a forecast under doubt","scenario":"The CFO doubts your commit number and pushes. You start to waffle and lower it on the spot to please them. If the number is right, presence is holding it and defending it with evidence — not caving to pressure.","task":"Write the 2-3 sentence response that holds the number and cites the evidence behind it.","tips":["Don't move a defensible number just because it's questioned.","Answer doubt with evidence, not a lower guess.","Caving instantly teaches everyone your numbers are soft."],"focus":["impact","precision"]},
    {"id":"presence-sales-mid-23","level":"mid","profession":"sales","title":"The 'my recommendation, your decision' frame","scenario":"You're advising your VP on whether to put a struggling rep on a plan. You want to own your recommendation without overstepping — it's the VP's call, but they want your honest view, not a shrug.","task":"Write the 2-3 sentence framing that owns the recommendation and defers the decision cleanly.","tips":["'My recommendation is X; it's your call' is a mature frame.","Give the recommendation with conviction, then step back.","Owning your view while respecting the decider is peak presence."],"focus":["impact","clarity"]},
    {"id":"presence-sales-mid-24","level":"mid","profession":"sales","title":"The confident close of a readout","scenario":"Your campaign readout trails off: 'so, yeah, that's kind of where we are, I guess.' A weak close erases a strong readout. End with the takeaway and the one thing you want the room to do.","task":"Write a 2-sentence close that states the takeaway and the ask with conviction.","tips":["Never end on 'that's it, I guess'.","Restate the one takeaway, then name the decision or action you want.","The close is what they carry out of the room."],"focus":["impact","clarity"]},
    {"id":"presence-sales-mid-25","level":"mid","profession":"sales","title":"The peer-to-peer disagreement","scenario":"In a leadership meeting the head of product asserts the launch date is firm; your field data says it'll hurt deals. Presence is disagreeing directly, in the room, with respect and evidence — not going along and grumbling after.","task":"Write the 2-3 sentence in-room disagreement: your position, the evidence, a constructive next step.","tips":["Disagree in the room, not in the hallway afterward.","Lead with respect and evidence, not with 'I think you're wrong'.","Offer a path forward, not just an objection."],"focus":["impact","clarity"]}
  ],
  "answering-under-pressure": [
    {"id":"pressure-sales-mid-01","level":"mid","profession":"sales","title":"'Will you hit the number?'","scenario":"On the forecast call the CRO cuts in: 'Simple question — will your team hit the number this quarter, yes or no?' You want to explain the pipeline first. They asked a yes/no.","task":"Answer the question asked first, in one word, then add the one condition.","tips":["Answer the actual question before the context.","Yes, no, or a bounded 'probably' — then the caveat.","Leading with context reads as dodging."],"focus":["clarity","structure"],"placeholder":"Yes — assuming Halvorsen closes; without it we're at 94%."},
    {"id":"pressure-sales-mid-02","level":"mid","profession":"sales","title":"The pushback on your discount ask","scenario":"You ask the VP to approve 20%. They push back: 'Why can't you win this at 10 like the last one?' You feel defensive. Answer with the specific difference, not with justification of your judgment.","task":"Write the 2-3 sentence response that meets the pushback with a specific reason.","tips":["Answer with the concrete difference between the deals.","Specifics disarm; defensiveness invites more pushback.","Name the competitor, the stakes, the math — not your feelings."],"focus":["clarity","precision"]},
    {"id":"pressure-sales-mid-03","level":"mid","profession":"sales","title":"'Why did this slip again?'","scenario":"The Meridian deal slips a second time and your CRO asks, pointedly, 'Why did this slip again?' Your instinct is to defend the rep and relitigate. Answer the question directly: the specific reason it slipped, then what's different now.","task":"Write the direct answer: the reason it slipped, no defensiveness, then the changed factor.","tips":["Answer the 'why' with the real cause, not a shield for the rep.","One cause, stated plainly, then what you've changed.","Defensiveness signals you don't have control of it."],"focus":["clarity","structure"]},
    {"id":"pressure-sales-mid-04","level":"mid","profession":"sales","title":"The 'I don't know' with a path","scenario":"In the campaign readout the CMO asks the exact multi-touch attribution for a deal and you don't have it. Bluffing is worse than not knowing. Say you don't know, and give the path to the answer.","task":"Write the 2-sentence honest 'I don't know' with a specific commitment to follow up.","tips":["Say you don't have it — cleanly, no waffle.","Attach a path: what you'll check and by when.","A confident 'I'll get that by end of day' beats a made-up number."],"focus":["clarity","structure"],"placeholder":"I don't have the exact touch breakdown — I'll pull it from the attribution report and send it by end of day."},
    {"id":"pressure-sales-mid-05","level":"mid","profession":"sales","title":"The hostile board question","scenario":"A board member challenges your marketing team: 'It sounds like you're just taking credit for deals sales would've closed anyway.' It stings. Answer the actual challenge — the incrementality question — with evidence, not indignation.","task":"Write the 2-3 sentence answer that addresses the incrementality question with data.","tips":["Answer the real question buried in the jab.","Bring the incrementality data, not wounded pride.","Composure under a hostile question is itself persuasive."],"focus":["clarity","precision"]},
    {"id":"pressure-sales-mid-06","level":"mid","profession":"sales","title":"'Is this rep going to make it?'","scenario":"Your VP asks bluntly whether the struggling rep will turn it around. You want to hedge to protect the rep. The VP needs your honest read, given clearly, with the evidence.","task":"Write the 2-3 sentence honest answer: your read, the basis, and the timeframe you'd give it.","tips":["Give your real read, not the diplomatic non-answer.","Ground it in the trend, not in hope.","Honest and specific serves the rep better than vague optimism."],"focus":["clarity","precision"]},
    {"id":"pressure-sales-mid-07","level":"mid","profession":"sales","title":"The customer's 'why should we trust you?'","scenario":"Mid-negotiation the customer's CFO says: 'Your last vendor promised the same thing and missed. Why are you different?' You want to bad-mouth the competitor. Answer with specifics about your delivery, not defensiveness.","task":"Write the 2-3 sentence answer grounded in concrete proof, not competitor bashing.","tips":["Answer with what you'll do differently, specifically.","Proof — a reference, a metric, a guarantee — beats reassurance.","Don't take the bait to trash the last vendor."],"focus":["clarity","impact"]},
    {"id":"pressure-sales-mid-08","level":"mid","profession":"sales","title":"'Why is coverage so low?'","scenario":"The CRO sees your 1.8x coverage and demands, sharply, why. You could blame marketing's lead flow. Answer the question honestly — the real drivers — then the plan, without pointing fingers.","task":"Write the direct answer: the two real drivers of the gap, then your plan, no blame.","tips":["Name the actual causes, including your own team's part.","Blaming another team reads as ducking accountability.","Follow the diagnosis immediately with the fix."],"focus":["clarity","structure"]},
    {"id":"pressure-sales-mid-09","level":"mid","profession":"sales","title":"The 'that's not good enough' moment","scenario":"You present a recovery plan and the CRO says flatly, 'That's not good enough.' You can crumble or get defensive. Instead, ask the sharpening question and respond to the real gap.","task":"Write the 2-3 sentence response that stays composed and gets to the specific shortfall.","tips":["Don't fold and don't argue — clarify the gap.","Ask what specifically falls short, then address it.","Composure here is more convincing than the plan itself."],"focus":["clarity","impact"]},
    {"id":"pressure-sales-mid-10","level":"mid","profession":"sales","title":"The trick 'just give me a number'","scenario":"A board member presses: 'Forget the caveats, just give me one pipeline number for next year.' Oversimplifying is a trap, but so is refusing. Give the number, then the single most important caveat in one clause.","task":"Write the answer: the number first, then the one caveat that actually matters.","tips":["Give the number they asked for — don't refuse.","Attach exactly one caveat, the load-bearing one.","One number plus one caveat is honest and usable."],"focus":["clarity","precision"],"placeholder":"$8.5M sourced pipeline — with the caveat that it assumes we keep marketing spend flat."},
    {"id":"pressure-sales-mid-11","level":"mid","profession":"sales","title":"The rep's angry challenge","scenario":"In a team meeting a rep challenges you: 'The new territory split screwed me and you know it.' The room is watching. Answer the substance calmly — was the split fair? — without matching the heat.","task":"Write the 2-3 sentence response that addresses the fairness question directly and calmly.","tips":["Answer the substance, not the tone.","Acknowledge what's valid, correct what isn't, with facts.","Staying calm while being challenged is a leadership signal."],"focus":["clarity","impact"]},
    {"id":"pressure-sales-mid-12","level":"mid","profession":"sales","title":"'Why should we keep funding this campaign?'","scenario":"Finance questions the paid-social spend mid-quarter: 'What have we actually gotten for this?' You want to cite activity metrics. They want pipeline and payback. Answer their question, not the one you prefer.","task":"Write the 2-3 sentence answer in the terms finance asked about: pipeline and payback.","tips":["Answer with the metric they care about, not the one that flatters.","Pipeline sourced and cost-per-dollar, not impressions.","Answering the actual question is what earns continued funding."],"focus":["clarity","audience"]},
    {"id":"pressure-sales-mid-13","level":"mid","profession":"sales","title":"The 'you promised' from a customer","scenario":"A customer exec says on a call: 'Your rep promised integration in 30 days and it's been 45.' It's true. Don't deflect to the engineering dependency. Own it, then give the concrete recovery.","task":"Write the 2-3 sentence response: own the miss, then the specific recovery date and step.","tips":["Own the broken commitment plainly — no 'well, technically'.","Deflecting to internal reasons makes it worse for the customer.","Follow the ownership with a concrete, dated recovery."],"focus":["clarity","impact"]},
    {"id":"pressure-sales-mid-14","level":"mid","profession":"sales","title":"The rapid-fire deal-review grilling","scenario":"In deal review your VP fires: 'Who's the economic buyer? What's the compelling event? Why now?' You have answers for two and not the third. Answer what you know crisply and flag the gap honestly.","task":"Write the crisp answers to the two you know and the honest flag on the third.","tips":["Answer the ones you know fast and cleanly.","Don't bluff the gap — name it as the thing you're chasing.","A clear 'don't know yet, here's how I'll find out' holds up."],"focus":["clarity","precision"]},
    {"id":"pressure-sales-mid-15","level":"mid","profession":"sales","title":"'Isn't this just spin?'","scenario":"You present a mixed quarter positively and a leader interrupts: 'This feels like spin — what's the real story?' Answer the challenge by giving the unvarnished version, immediately, without getting defensive.","task":"Write the 2-3 sentence unvarnished answer that meets the accusation head-on.","tips":["Meet 'is this spin?' by dropping the spin instantly.","Give the plain version — including the bad part.","Defensiveness confirms the suspicion; candor kills it."],"focus":["clarity","structure"]},
    {"id":"pressure-sales-mid-16","level":"mid","profession":"sales","title":"The 'what would you cut?' test","scenario":"Asked to defend your budget, the CFO says: 'If I gave you 20% less, what would you cut?' A non-answer ('everything's essential') fails. Answer honestly with the specific tradeoff and its cost.","task":"Write the 2-3 sentence answer naming what you'd cut and what it would cost in pipeline.","tips":["'Nothing' is not a credible answer — pick something.","Name the cut and quantify what it forfeits.","A real answer shows you know your own priorities."],"focus":["clarity","precision"],"placeholder":"I'd cut the fall trade show — it saves $80k but costs us about $200k in sourced pipeline."},
    {"id":"pressure-sales-mid-17","level":"mid","profession":"sales","title":"The interruption that changes the question","scenario":"You're two minutes into explaining the pipeline when the CRO interrupts: 'I don't care about the pipeline, I care whether the Q4 renewal cohort is safe.' Drop your prepared answer and answer the new question.","task":"Write the pivot: acknowledge the redirect and answer the renewal question directly.","tips":["Abandon your script; answer the question now on the table.","Don't finish your point first — that reads as not listening.","A clean pivot shows you're tracking what they need."],"focus":["clarity","audience"]},
    {"id":"pressure-sales-mid-18","level":"mid","profession":"sales","title":"'Are you sandbagging?'","scenario":"Your commit looks conservative and the CRO asks, half-accusing, 'Are you sandbagging me?' You want to over-explain your methodology. Answer the question — no or yes — then the one-line reason your number is what it is.","task":"Write the direct answer to the accusation, then the one-sentence basis.","tips":["Answer the actual question: no, and here's why it's realistic.","One line on your basis — not a methodology lecture.","A straight answer to a pointed question builds trust."],"focus":["clarity","structure"]},
    {"id":"pressure-sales-mid-19","level":"mid","profession":"sales","title":"The customer's price ultimatum","scenario":"The customer says: 'Match their price by Friday or we walk.' You feel cornered. Don't cave and don't bluff. Answer with what you can and can't do, and reframe to value, calmly.","task":"Write the 2-3 sentence response that holds your line and redirects to value under pressure.","tips":["Don't panic-discount; state what you can actually do.","Reframe to the total cost, not the headline price.","Composure under an ultimatum often reveals it's not real."],"focus":["clarity","impact"]},
    {"id":"pressure-sales-mid-20","level":"mid","profession":"sales","title":"The 'why should I believe your forecast?'","scenario":"You missed last quarter and now the CFO asks why they should trust this quarter's forecast. Fair question. Answer it with what specifically changed in how you forecast — not with reassurance.","task":"Write the 2-3 sentence answer citing the concrete change in your forecasting, not promises.","tips":["Earn trust with a process change, not a pledge.","Name what you now do differently — tighter commit criteria, weekly scrubs.","Reassurance without a changed method is just hope."],"focus":["clarity","precision"]},
    {"id":"pressure-sales-mid-21","level":"mid","profession":"sales","title":"The blindside stat","scenario":"In the QBR someone drops a stat you haven't seen — 'your segment's win rate actually fell.' You don't know if it's right. Don't accept it blindly or dismiss it. Ask the clarifying question and commit to reconciling it.","task":"Write the composed 2-sentence response that neither concedes nor denies, and sets up a check.","tips":["Don't accept an unverified stat about your own team.","Ask what timeframe and denominator it uses.","Commit to reconcile and follow up — don't argue live."],"focus":["clarity","precision"]},
    {"id":"pressure-sales-mid-22","level":"mid","profession":"sales","title":"'Your team is the problem'","scenario":"A cross-functional leader says in a meeting that sales is the bottleneck on launches. You feel attacked on behalf of your team. Answer the substance — where's the actual delay? — without escalating the blame.","task":"Write the 2-3 sentence response that engages the substance and de-escalates.","tips":["Address the specific claim, not the accusatory framing.","Acknowledge any true part; correct the rest with facts.","De-escalating while standing up for your team is the skill."],"focus":["clarity","impact"]},
    {"id":"pressure-sales-mid-23","level":"mid","profession":"sales","title":"The 'just yes or no' on a nuanced call","scenario":"'Should we extend the promotion — yes or no?' It's genuinely nuanced, but the CRO wants a decision. Give your yes or no first, then the single most important nuance — don't hide behind 'it's complicated.'","task":"Write the answer: a clear yes or no, then the one nuance that qualifies it.","tips":["Commit to a side first; you can still qualify it.","'It's complicated' is not a decision — give one anyway.","One nuance after the verdict shows judgment, not indecision."],"focus":["clarity","structure"],"placeholder":"Yes — but only for the enterprise segment, where it's actually moving deals."},
    {"id":"pressure-sales-mid-24","level":"mid","profession":"sales","title":"The follow-up you can't answer live","scenario":"After your recommendation the VP asks a second-order question you haven't modeled: 'What does this do to next year's comp cost?' Don't guess a number on the spot. Acknowledge it's a fair question and commit to the analysis.","task":"Write the 2-sentence honest response that takes the question seriously without a made-up answer.","tips":["Don't fabricate a figure under pressure.","Validate the question — it's the right one to ask.","Commit to run it and come back with a real number."],"focus":["clarity","structure"]},
    {"id":"pressure-sales-mid-25","level":"mid","profession":"sales","title":"The layered attribution challenge","scenario":"In front of the CEO, sales and marketing both claim a $900k deal. The CEO looks at you and asks: 'So did your campaign actually drive this or not?' Answer the direct question honestly, even if the honest answer shares credit.","task":"Write the 2-3 sentence honest answer to whether the campaign drove the deal.","tips":["Answer the yes/no honestly, even if it's 'partly'.","Sharing credit honestly reads as more credible than claiming all.","Don't relitigate the touchpoints — answer the question asked."],"focus":["clarity","structure"]}
  ],
  "narrative-and-persuasion": [
    {"id":"narrative-sales-mid-01","level":"mid","profession":"sales","title":"The before/after for headcount","scenario":"Your case for two more AEs is a list of reasons. It doesn't move your VP. Frame it as a change: today reps turn away qualified pipeline; with two hires, that pipeline converts. Make the gap between the two states vivid.","task":"Write the before/after: one sentence on the current state, one on the after, one on the cost of the gap.","tips":["Contrast makes the case: this is now, this is possible.","Make the 'before' a real loss, not a neutral status.","The gap between them is the size of your ask's payoff."],"focus":["impact","structure"],"placeholder":"Today we turn away roughly $2M in qualified pipeline a quarter for lack of capacity."},
    {"id":"narrative-sales-mid-02","level":"mid","profession":"sales","title":"Concrete stakes for the budget shift","scenario":"You want to move budget to paid search. 'It's more efficient' is abstract. Make the stakes concrete: at current spend, the inefficiency costs the equivalent of two AEs' worth of pipeline a year, going to waste.","task":"Write the 2-3 sentence pitch that makes the cost of not shifting concrete and vivid.","tips":["Translate 'inefficient' into something they can picture.","Peg the waste to a unit they feel — headcount, deals, quota.","Concrete stakes create urgency abstractions can't."],"focus":["impact","precision"]},
    {"id":"narrative-sales-mid-03","level":"mid","profession":"sales","title":"Pre-empt the strongest objection","scenario":"Pitching the new vertical to your CRO, you know their strongest objection is compliance overhead. Don't wait for it. Raise it yourself, address it, and turn addressing it into part of your case.","task":"Write the 2-3 sentences that name the compliance objection and dismantle it before they raise it.","tips":["Name their best objection before they do — it disarms it.","Address it with a specific mitigation, not a wave.","Pre-empting shows you've thought it through, which builds trust."],"focus":["impact","structure"]},
    {"id":"narrative-sales-mid-04","level":"mid","profession":"sales","title":"The customer's story, not your features","scenario":"Your pitch to a prospect leads with your product's capabilities. It's forgettable. Reframe it as their story: where they are stuck, what changes when the problem is solved, what that's worth to them.","task":"Write the 3-sentence narrative arc: their stuck state, the change, the payoff — features only as support.","tips":["The hero is the customer, not your product.","The 'after' is their business improved, not your feature list.","Features are how the change happens, mentioned last."],"focus":["impact","audience"]},
    {"id":"narrative-sales-mid-05","level":"mid","profession":"sales","title":"The reference story with a turn","scenario":"You're writing a customer win story for the sales team to use. Your draft is a flat description. A story needs a turn: they were failing at X, then something changed, and now the result is measurable.","task":"Write the 3-beat story: the painful before, the turning point, the quantified after.","tips":["Open in the pain — make the before uncomfortable.","The turn is the specific moment things changed.","The after must carry a number a prospect envies."],"focus":["impact","clarity"]},
    {"id":"narrative-sales-mid-06","level":"mid","profession":"sales","title":"Persuading the skeptical rep","scenario":"You're rolling out a new discovery framework and your best rep thinks it'll slow them down. Persuade with a before/after they'll feel: more discovery up front means fewer deals dying at procurement later.","task":"Write the 2-3 sentence pitch framed around what the rep gains, with the objection pre-empted.","tips":["Frame the change around their win, not the org's process.","Pre-empt 'it slows me down' with the downstream payoff.","Persuasion is showing the after is better for them."],"focus":["impact","audience"]},
    {"id":"narrative-sales-mid-07","level":"mid","profession":"sales","title":"The launch story for the field","scenario":"You're rallying the team behind the new product. Reciting features won't do it. Tell the story: here's the deal we've been losing, here's what this changes, here's the deal we'll win now.","task":"Write the 3-sentence rally narrative anchored in a deal type they lose today.","tips":["Anchor in a loss they recognize from real deals.","Show precisely what the new thing changes in that fight.","End on the win now available — make it feel within reach."],"focus":["impact","clarity"]},
    {"id":"narrative-sales-mid-08","level":"mid","profession":"sales","title":"Making the churn risk vivid","scenario":"You're asking leadership to fund a retention play. 'Churn is a risk' is background noise. Make it vivid: name the cohort, the dollars walking out the door this quarter, and what one saved account is worth.","task":"Write the 2-3 sentence case that makes the churn stakes concrete and urgent.","tips":["Put a face and a number on the risk — a named cohort, real dollars.","Contrast the cost of acting with the cost of not.","Vivid and specific beats 'churn is up' every time."],"focus":["impact","precision"],"placeholder":"Eight accounts worth $1.2M are up for renewal in 60 days with declining usage — that's the churn we can still stop."},
    {"id":"narrative-sales-mid-09","level":"mid","profession":"sales","title":"The comp-change persuasion","scenario":"The new comp plan pays for retention, not just new logos, and reps are suspicious. Persuade them by framing the before/after: today they lose renewal upside; under the new plan, keeping accounts pays them directly.","task":"Write the 2-3 sentence pitch that reframes the change as a gain for the rep.","tips":["Lead with what the change adds to their paycheck, not what it moves.","Contrast the old blind spot with the new upside.","Address the suspicion by naming it and answering it."],"focus":["impact","audience"]},
    {"id":"narrative-sales-mid-10","level":"mid","profession":"sales","title":"The exec-sponsor ask, dramatized","scenario":"You need your SVP to make one call to save a strategic renewal. A dry request gets deprioritized. Frame the stakes as a story: this account is one call away from staying or leaving, and only the SVP can make it.","task":"Write the 2-3 sentence ask that dramatizes the stakes and makes the SVP the pivotal actor.","tips":["Make the SVP the one who tips the outcome.","Frame it as a fork: their call decides which way this goes.","Concrete stakes plus a clear, small ask gets action."],"focus":["impact","clarity"]},
    {"id":"narrative-sales-mid-11","level":"mid","profession":"sales","title":"Pre-empting the 'we already have a tool'","scenario":"Your prospect will say they already have a solution. Don't wait to be told. Open by acknowledging their current tool, then frame the specific gap it leaves — the gap your product fills.","task":"Write the 2-3 sentence open that pre-empts the incumbent objection and reframes to the gap.","tips":["Acknowledge the incumbent — arguing it doesn't exist fails.","Name the specific gap it leaves, from their world.","Reframe from 'replace your tool' to 'close this gap'."],"focus":["impact","audience"]},
    {"id":"narrative-sales-mid-12","level":"mid","profession":"sales","title":"The QBR story arc","scenario":"Your QBR is a data recap with no arc. Give it a narrative: we started the quarter facing a coverage problem, we made three moves, and here's where it landed. Make leadership feel the journey, not just the numbers.","task":"Write the 3-sentence QBR arc: the challenge we faced, the moves we made, the outcome.","tips":["A QBR with a story is remembered; a data dump isn't.","Open on the real problem the quarter posed.","Land on the outcome as the resolution of that problem."],"focus":["impact","structure"]},
    {"id":"narrative-sales-mid-13","level":"mid","profession":"sales","title":"Making the SLA breach matter","scenario":"You want sales managers to fix slow lead follow-up. 'Improve your SLA' is ignorable. Make it matter: every hour a hot lead waits, conversion drops, and you can show the leads lost to the delay last month.","task":"Write the 2-3 sentence case that makes the cost of slow follow-up concrete and personal.","tips":["Tie the abstract SLA to lost deals they'd have wanted.","Use a real number: leads lost last month to slow touch.","Make it their pipeline bleeding, not a policy metric."],"focus":["impact","audience"]},
    {"id":"narrative-sales-mid-14","level":"mid","profession":"sales","title":"The 'why now' for the new hire req","scenario":"Your headcount ask is sound but timeless — it could be asked any quarter. Persuasion needs a 'why now': the inbound surge is here, it won't wait, and every week without the hire is pipeline aging out.","task":"Write the 2-3 sentences that establish urgency — why this must happen now, not next quarter.","tips":["A request without urgency gets deferred indefinitely.","Anchor 'now' to a real, time-bound trigger.","Show the cost of each week of delay."],"focus":["impact","clarity"]},
    {"id":"narrative-sales-mid-15","level":"mid","profession":"sales","title":"The objection you keep losing to","scenario":"Reps keep losing to 'you're too expensive' and folding. Build the counter-narrative they can carry: reframe from price to the cost of the status quo, and make that cost vivid and specific to the buyer.","task":"Write the 2-3 sentence reframe from price to cost-of-inaction that a rep could say aloud.","tips":["Move the frame from your price to their current bleed.","Make the status-quo cost concrete — hours, errors, churn.","Give the rep words they can say naturally in the moment."],"focus":["impact","clarity"]},
    {"id":"narrative-sales-mid-16","level":"mid","profession":"sales","title":"The campaign pitch to the CMO","scenario":"You're pitching a bold new campaign to the CMO. A feature-and-tactics list won't win the budget. Frame it as a change in the market position: here's how buyers see us now, here's how they'd see us after.","task":"Write the 3-sentence pitch: the current perception, the shift the campaign creates, the business payoff.","tips":["Sell the perception shift, not the tactics.","Contrast the before and after in the buyer's mind.","Land on what the shift is worth in pipeline or price."],"focus":["impact","clarity"]},
    {"id":"narrative-sales-mid-17","level":"mid","profession":"sales","title":"Pre-empting the ROI doubt","scenario":"Your customer's CFO will doubt your ROI numbers. Don't present them and hope. Pre-empt: acknowledge that vendor ROI claims are usually inflated, then show why yours is conservative and how they can verify it.","task":"Write the 2-3 sentences that pre-empt ROI skepticism and build credibility for your number.","tips":["Name the skepticism — 'you've heard inflated claims before'.","Show your number is conservative, with the assumptions visible.","Offer a way for them to verify it themselves."],"focus":["impact","precision"]},
    {"id":"narrative-sales-mid-18","level":"mid","profession":"sales","title":"The territory-change story for a rep","scenario":"You're moving accounts out of a rep's patch and they'll feel it as a loss. Frame the change as a trade with a payoff for them: fewer accounts, but the ones they keep are higher-value and better-fit.","task":"Write the 2-3 sentence framing that turns a loss into a defensible trade with an upside.","tips":["Acknowledge the loss honestly — don't pretend it isn't one.","Show the offsetting gain concretely.","A trade they can see the logic of beats a decree."],"focus":["impact","audience"]},
    {"id":"narrative-sales-mid-19","level":"mid","profession":"sales","title":"The all-hands win, told as a story","scenario":"You're presenting the year's biggest win at the all-hands. Reciting the numbers is flat. Tell it as a story: the customer no one thought we'd land, the moment it turned, what it means for the company.","task":"Write the 3-sentence story arc for the win that a non-sales audience will feel.","tips":["Open on the underdog framing — why it was hard.","Give the turning-point moment, human and specific.","Close on what it proves about the company's trajectory."],"focus":["impact","audience"]},
    {"id":"narrative-sales-mid-20","level":"mid","profession":"sales","title":"The reallocation nobody wants to hear","scenario":"You're cutting the beloved trade-show budget. People are attached. Persuade by framing the change as a choice between two futures: one where the money keeps buying diminishing returns, one where it buys growing pipeline.","task":"Write the 2-3 sentence framing that makes the reallocation feel like a smart choice, not a loss.","tips":["Frame it as choosing the better future, not killing the old one.","Honor the attachment before making the case.","Contrast the two futures with real numbers."],"focus":["impact","clarity"]},
    {"id":"narrative-sales-mid-21","level":"mid","profession":"sales","title":"The stakes of the coverage gap","scenario":"You're asking leadership to invest in top-of-funnel now. 'Coverage is low' is a number without weight. Make the stakes felt: without action, the quarter after next is already lost, and you can show the math.","task":"Write the 2-3 sentence case that makes a future shortfall feel present and urgent.","tips":["Make a future problem feel like a present emergency.","Show the lead time — why acting later is acting too late.","Anchor the stakes to a specific future quarter's number."],"focus":["impact","precision"],"placeholder":"With today's coverage, Q1 next year is already 20% short — and pipeline built now is the only fix in time."},
    {"id":"narrative-sales-mid-22","level":"mid","profession":"sales","title":"Persuading product to prioritize a gap","scenario":"You need product to build a capability that's costing deals. A feature request gets queued and forgotten. Frame it as a story with stakes: the deals lost, the segment blocked, the revenue waiting on this one thing.","task":"Write the 2-3 sentence pitch that gives the feature request narrative weight and stakes.","tips":["Attach the gap to lost revenue and a blocked segment.","Make it a story of what's stuck, not a line-item ask.","Pre-empt 'is it really that many deals?' with the count."],"focus":["impact","clarity"]},
    {"id":"narrative-sales-mid-23","level":"mid","profession":"sales","title":"The renewal case as a story","scenario":"You're building the renewal business case for a customer's CFO. A usage report is forgettable. Tell the story of the year: where they were, what the platform changed, and what walking away would cost them now.","task":"Write the 3-sentence renewal narrative: the before, the change delivered, the cost of leaving.","tips":["Remind them where they started — before your product.","Show the change in their terms, measured.","Frame non-renewal as giving up a gain, not saving a cost."],"focus":["impact","clarity"]},
    {"id":"narrative-sales-mid-24","level":"mid","profession":"sales","title":"The 'why us' that pre-empts the competitor","scenario":"You're in a bake-off and the customer likes a cheaper competitor. Don't ignore them. Frame your 'why us' by pre-empting the competitor's pitch and showing where their approach breaks for this customer specifically.","task":"Write the 2-3 sentence differentiator that pre-empts the competitor and reframes to fit.","tips":["Name the competitor's appeal honestly, then its limit here.","Anchor the difference to this customer's specific situation.","Reframe from 'cheaper' to 'right for you'."],"focus":["impact","audience"]},
    {"id":"narrative-sales-mid-25","level":"mid","profession":"sales","title":"The team-motivation story mid-slump","scenario":"Your team is in a slump and morale is low. A pep talk of clichés won't land. Tell a real before/after: name where you were three quarters ago, what the team overcame, and why this slump is the same shape.","task":"Write the 3-sentence motivational narrative grounded in a real past comeback.","tips":["Ground motivation in a real, specific past win.","Draw the parallel to the current slump honestly.","End on the concrete next move, not just uplift."],"focus":["impact","clarity"]}
  ],
  "delivering-hard-messages": [
    {"id":"hard-sales-mid-01","level":"mid","profession":"sales","title":"The performance-plan conversation","scenario":"You have to tell a rep who's missed three quarters that they're going on a formal performance plan. Your draft opens with two paragraphs of reassurance that buries the message. Clear is kind — front-load it.","task":"Write the opening two sentences that state the news plainly, without cushioning it into confusion.","tips":["Say the hard thing first, in plain words.","Cushioning so much they miss the message isn't kindness.","Clarity now spares them a worse surprise later."],"focus":["clarity","impact"],"placeholder":"I'm putting you on a formal performance plan, effective Monday. I want to be direct about why and what it takes to come off it."},
    {"id":"hard-sales-mid-02","level":"mid","profession":"sales","title":"The clean no to a discount","scenario":"A rep asks you to approve a 30% discount you won't give. Your instinct is to hedge with 'let me see' and drag it out. A clean, quick no with the reason serves them better than a slow maybe.","task":"Write the 2-sentence clean no: the decision and the one reason, no false hope.","tips":["Say no clearly — 'let me think about it' when you won't is cruel.","Give the reason so it's a decision, not a whim.","A fast no lets them pivot; a slow maybe wastes the deal."],"focus":["clarity","impact"],"placeholder":"No on 30% — it sets a precedent we can't hold. I can approve 15% with a two-year term."},
    {"id":"hard-sales-mid-03","level":"mid","profession":"sales","title":"Behavior, impact, ask — the missed forecast","scenario":"A rep consistently over-commits deals that then slip, hurting your credibility on forecast calls. You need to give feedback using behavior → impact → ask, not a vague 'be more careful.'","task":"Write the feedback: the specific behavior, its impact, and the concrete ask.","tips":["Name the behavior observably: committing deals without a close date.","State the impact on you and the team, specifically.","End with a clear ask, not 'do better'."],"focus":["clarity","precision"]},
    {"id":"hard-sales-mid-04","level":"mid","profession":"sales","title":"Telling leadership you'll miss","scenario":"You now know you'll finish the quarter at 92%. Leadership doesn't know yet. Every day you delay makes it worse. Deliver the bad news early, plainly, with the cause and the plan — don't wait for the last forecast call.","task":"Write the 3-sentence early warning: the miss, the cause, the plan, delivered now.","tips":["Bad news delivered early is a courtesy; delivered late is a betrayal.","State the number without softening it.","Pair it immediately with the cause and the recovery."],"focus":["clarity","impact"]},
    {"id":"hard-sales-mid-05","level":"mid","profession":"sales","title":"The customer whose ask you must decline","scenario":"A customer wants a custom feature you won't build. Stringing them along with 'we'll look into it' is worse than a clear no. Decline honestly, explain briefly, and offer what you can do instead.","task":"Write the 2-3 sentence decline: the honest no, the reason, the alternative.","tips":["A false 'we'll consider it' erodes trust when it never comes.","Say no, give a real reason, then pivot to a workaround.","Customers respect a straight answer over a hopeful stall."],"focus":["clarity","audience"]},
    {"id":"hard-sales-mid-06","level":"mid","profession":"sales","title":"The territory-cut delivered to a rep","scenario":"You're taking two accounts from a rep's territory and they'll be upset. Softening it into ambiguity leaves them confused and more anxious. State the change clearly, own the reason, then hear them out.","task":"Write the opening that delivers the change plainly and invites the conversation.","tips":["State exactly what's changing — no euphemisms.","Own the reason; don't hide behind 'leadership decided'.","Then genuinely open the floor to their reaction."],"focus":["clarity","impact"]},
    {"id":"hard-sales-mid-07","level":"mid","profession":"sales","title":"The 'no' to a peer team's request","scenario":"Product asks your team to run an unplanned enablement push that would derail quota focus. You need to decline a peer team cleanly, without a passive-aggressive maybe or a resentful yes.","task":"Write the 2-3 sentence clean no to product that preserves the relationship.","tips":["Decline clearly and explain the tradeoff honestly.","A resentful yes damages more than a respectful no.","Offer a smaller version or a later slot if one exists."],"focus":["clarity","audience"]},
    {"id":"hard-sales-mid-08","level":"mid","profession":"sales","title":"Firing feedback: the deal you lost badly","scenario":"A rep lost a winnable deal through poor discovery and you need to debrief it honestly. Sugar-coating means they learn nothing. Deliver the hard assessment kindly but clearly, focused on the fixable behavior.","task":"Write the 2-3 sentence debrief: the honest assessment and the specific lesson, kindly delivered.","tips":["Be honest about what went wrong — vagueness protects no one.","Focus on the behavior and the fix, not the person.","Kind and clear aren't opposites; be both."],"focus":["clarity","impact"]},
    {"id":"hard-sales-mid-09","level":"mid","profession":"sales","title":"The customer escalation you caused","scenario":"Your team over-promised a timeline and the customer is furious. You have to own it to their exec. Front-load the acknowledgment — don't bury it under context — then the concrete fix.","task":"Write the 2-3 sentence message that owns the mistake up front and commits to the fix.","tips":["Lead with the acknowledgment, not the explanation.","Own it plainly — 'we got this wrong' — before the fix.","Context can follow; the apology comes first."],"focus":["clarity","impact"]},
    {"id":"hard-sales-mid-10","level":"mid","profession":"sales","title":"Telling a rep they're not getting the promotion","scenario":"A rep expected a senior-AE promotion and isn't getting it this cycle. Dodging or over-softening leaves them without a path. Deliver the decision clearly, the honest reason, and the specific route forward.","task":"Write the 3-sentence message: the decision, the real reason, the path to earn it.","tips":["State the decision without burying it in praise.","Give the actual reason — vague reasons feel like rejection.","End with the concrete criteria for next cycle."],"focus":["clarity","precision"]},
    {"id":"hard-sales-mid-11","level":"mid","profession":"sales","title":"The quota that's going up","scenario":"You're delivering a 15% quota increase to a rep who'll feel it as unfair. Hedging it makes it feel arbitrary. State the number, own it, and explain the support that comes with it — clearly, not apologetically.","task":"Write the 2-3 sentence delivery: the new number, owned, plus the support attached.","tips":["Say the number plainly; don't apologize for it.","Own it as a decision, not something that happened to you both.","Pair the harder target with the concrete support for it."],"focus":["clarity","impact"]},
    {"id":"hard-sales-mid-12","level":"mid","profession":"sales","title":"The 'we're deprioritizing your account' message","scenario":"A small customer wants white-glove attention you can't sustainably give. You need to reset expectations honestly rather than keep over-serving and quietly resenting it. Clear boundaries, kindly stated.","task":"Write the 2-3 sentence expectation reset that's honest about what they will and won't get.","tips":["Be honest about the level of service they'll get.","A clear boundary beats silent under-delivery.","Frame it around what they can rely on, not what they lose."],"focus":["clarity","audience"]},
    {"id":"hard-sales-mid-13","level":"mid","profession":"sales","title":"The layoff conversation for a team member","scenario":"Budget cuts mean one of your reps is being let go, and you're delivering the news. This demands maximum clarity and humanity: no burying it, no false hope, respect throughout.","task":"Write the opening two sentences that deliver the news clearly and with dignity.","tips":["Say it plainly and early — dragging it out is cruel.","No false hope, no 'maybe if things change'.","Respect and clarity are the whole job here."],"focus":["clarity","impact"]},
    {"id":"hard-sales-mid-14","level":"mid","profession":"sales","title":"The feedback about a bad meeting habit","scenario":"A rep dominates team meetings and shuts down others. Using behavior → impact → ask keeps it specific and non-personal. Vague 'be more collaborative' won't change anything.","task":"Write the feedback: the specific behavior, the impact on the team, the concrete ask.","tips":["Describe the behavior with an example, not a label.","Name the impact — others stopped contributing.","Ask for one specific change they can practice."],"focus":["clarity","precision"]},
    {"id":"hard-sales-mid-15","level":"mid","profession":"sales","title":"Declining the customer's unreasonable term","scenario":"A big prospect demands an unlimited-liability clause your company won't accept. You must say no on a term they care about without torpedoing the deal. Clear no, real reason, alternative.","task":"Write the 2-3 sentence decline that holds the line and offers a viable alternative.","tips":["Say no to the term clearly — hedging invites more pressure.","Explain the reason as a company standard, not a personal call.","Offer the alternative you can actually stand behind."],"focus":["clarity","impact"]},
    {"id":"hard-sales-mid-16","level":"mid","profession":"sales","title":"Telling your VP their pet initiative isn't working","scenario":"Your VP championed a campaign that's underperforming and you have the data. Softening it wastes money; blunt-with-no-tact stings. Deliver the hard truth clearly, with the evidence and a recommendation.","task":"Write the 2-3 sentence message that delivers the bad result honestly and recommends a change.","tips":["Lead with the result, not a preamble that softens it away.","Bring the evidence so it's not about opinion.","Pair the bad news with a clear recommended change."],"focus":["clarity","precision"]},
    {"id":"hard-sales-mid-17","level":"mid","profession":"sales","title":"The 'your deal isn't real' verdict","scenario":"A rep keeps forecasting a deal you're convinced is dead. You need to tell them to pull it from the forecast — a message they don't want to hear. Clear is kind: say it, with the reasons.","task":"Write the 2-3 sentence message that delivers the verdict and the reasons plainly.","tips":["State the call clearly: pull it from commit.","Give the specific reasons the deal isn't real.","Let them keep working it — but not counting it."],"focus":["clarity","precision"]},
    {"id":"hard-sales-mid-18","level":"mid","profession":"sales","title":"Owning a mistake to a customer exec","scenario":"Your rep quoted the wrong price and the customer built a budget around it. You've decided you can't honor it and must tell their exec. Front-load the bad news and the ownership, then the resolution.","task":"Write the 3-sentence message: own the error, state what you can do, respect their position.","tips":["Own the mistake before explaining how it happened.","Be clear about what you can and can't do — no waffling.","Acknowledge the inconvenience you've caused them."],"focus":["clarity","impact"]},
    {"id":"hard-sales-mid-19","level":"mid","profession":"sales","title":"The no to a rep's expense request","scenario":"A rep wants budget for a lavish customer event you can't justify. A wishy-washy answer invites re-asking. Give a clean no with the reasoning and, if possible, what you would approve.","task":"Write the 2-3 sentence clean no with the reasoning and any acceptable alternative.","tips":["Decline clearly so it isn't re-litigated next week.","Explain the reasoning — it's a standard, not a mood.","Offer what you would approve, if anything."],"focus":["clarity","concision"]},
    {"id":"hard-sales-mid-20","level":"mid","profession":"sales","title":"Redirecting a rep's blame","scenario":"A rep blames marketing and product for their miss, and some of that is deflection. You need to name that behavior — the deflection — clearly and kindly, and redirect to what they control.","task":"Write the feedback: name the deflection behavior, its impact, and the redirect to their ownership.","tips":["Name the pattern without attacking the person.","Acknowledge any true external factor before the redirect.","Ask them to focus on the levers they actually hold."],"focus":["clarity","impact"]},
    {"id":"hard-sales-mid-21","level":"mid","profession":"sales","title":"The comp-error correction","scenario":"A rep was overpaid commission due to a system error and you must claw it back. This is delicate. Deliver it clearly, own the company's mistake, and explain the correction plainly rather than hiding it in HR-speak.","task":"Write the 2-3 sentence message that delivers the correction honestly and owns the error.","tips":["Own that it was the company's error, not their fault.","State the correction plainly — no burying it in jargon.","Be clear on the amount and the timeline."],"focus":["clarity","impact"]},
    {"id":"hard-sales-mid-22","level":"mid","profession":"sales","title":"Telling marketing their leads aren't converting","scenario":"You need to tell your marketing peer that their recent lead source converts poorly, and it's a hard message between allies. Front-load it with data, not accusation, and frame it as a shared problem to solve.","task":"Write the 2-3 sentence message that delivers the hard data honestly and collaboratively.","tips":["Lead with the number, framed as a shared issue.","Avoid blame — you both want conversion up.","End with an invitation to fix it together."],"focus":["clarity","audience"]},
    {"id":"hard-sales-mid-23","level":"mid","profession":"sales","title":"The 'not this quarter' to an eager rep","scenario":"A rep is pushing hard for a stretch assignment they're not ready for. Saying a vague 'maybe later' feels kind but isn't. Give a clear not-yet, the honest reason, and what readiness looks like.","task":"Write the 2-3 sentence not-yet: the decision, the reason, the path to yes.","tips":["'Not yet' is clearer and kinder than a soft 'maybe'.","Give the specific gap between now and ready.","Make the path concrete so it's motivating, not deflating."],"focus":["clarity","precision"]},
    {"id":"hard-sales-mid-24","level":"mid","profession":"sales","title":"The escalation about your own manager's ask","scenario":"Your VP asked you to push the team toward numbers you believe are unrealistic and harmful. You need to raise it with them directly and respectfully — a hard message upward. Front-load the concern with evidence.","task":"Write the 2-3 sentence upward message that raises the concern clearly and constructively.","tips":["Raise it directly — quiet resentment helps no one.","Lead with evidence, not just discomfort.","Offer an alternative, not only an objection."],"focus":["clarity","impact"]},
    {"id":"hard-sales-mid-25","level":"mid","profession":"sales","title":"The 'we're losing you' to a slipping star","scenario":"Your top rep has been disengaged and you suspect they're interviewing elsewhere. You want to have the honest conversation rather than pretend you don't notice. Name what you've observed, its impact, and open a real dialogue.","task":"Write the opening two sentences that name the observation honestly and invite a candid conversation.","tips":["Name what you've seen without accusation.","State that you value them — but be specific about the concern.","Open a genuine two-way conversation, not a lecture."],"focus":["clarity","impact"]}
  ],
  "putting-it-together": [
    {"id":"together-sales-mid-01","level":"mid","profession":"sales","title":"The end-of-quarter CRO email","scenario":"You're writing the quarter-close email to your CRO under real constraints: they'll read it on a phone between meetings. It needs the number, the story, the risks, and one ask — clear, lead-first, and short.","task":"Write the full 4-5 sentence email: result up front, brief cause, one risk, one ask.","tips":["Lead with the number; you know they scan for it first.","One sentence of story, one risk, one ask — no more.","Edit it as the CRO will read it: fast, on a small screen."],"focus":["structure","concision"]},
    {"id":"together-sales-mid-02","level":"mid","profession":"sales","title":"The forecast call, all together","scenario":"You have four minutes in the forecast call. You need to lead with the number, signpost your structure, answer likely pushback with specifics, and own one recommendation — everything from every module, live.","task":"Write the 4-5 sentence spoken segment that does all of it: number, signpost, evidence, recommendation.","tips":["Open with the number and a two-part signpost.","Bring the one figure that pre-empts the obvious challenge.","Close by owning a recommendation, not trailing off."],"focus":["structure","impact"]},
    {"id":"together-sales-mid-03","level":"mid","profession":"sales","title":"Match the register: Slack vs board","scenario":"You have the same news — pipeline is up but conversion dipped — to deliver in a quick Slack to your team and in a line for the board deck. Same facts, different register and altitude for each.","task":"Write the one-line Slack version and the one-line board version of the same news.","tips":["Slack: casual, direct, action-oriented for the team.","Board: assertion plus number, no internal jargon.","Same truth, register matched to each channel."],"focus":["audience","concision"]},
    {"id":"together-sales-mid-04","level":"mid","profession":"sales","title":"The campaign readout, fully built","scenario":"Your quarterly campaign readout to leadership must lead with the result, carry a governing idea with three supports, use precise numbers, and end with an owned recommendation — in three minutes.","task":"Write the readout's opening and close: the lead result, the governing idea, and the owned recommendation.","tips":["Lead with the outcome; structure the middle around one idea.","Numbers, not adjectives, throughout.","Close by recommending the next move, owned."],"focus":["structure","impact"]},
    {"id":"together-sales-mid-05","level":"mid","profession":"sales","title":"The escalation done right","scenario":"A strategic deal is at risk and you're escalating to your SVP. Pull it all together: lead with the ask, structure it (situation, impact, ask), be precise about the risk, and pre-empt the 'have you tried X' objection.","task":"Write the full 4-sentence escalation that integrates all of it.","tips":["Ask first, then situation and impact in one line each.","Quantify the risk precisely.","Pre-empt the obvious 'did you try' in a clause."],"focus":["structure","precision"]},
    {"id":"together-sales-mid-06","level":"mid","profession":"sales","title":"Edit like a reader: the bloated update","scenario":"Here's your draft launch update: 'Hey everyone, hope you're well! Wanted to share a quick update on where things stand with the launch, which as you know has been a big priority. We're making good progress on most fronts, though there are a few things still in flight...' Cut and sharpen it.","task":"Rewrite the update as a reader would want it: status, one risk, one ask, in under 40 words.","tips":["Delete the greeting and the meta-commentary.","Lead with status; name the one real risk.","Read your own draft as its busiest recipient would."],"focus":["concision","clarity"],"placeholder":"Launch is on track for the 14th. One risk: customer comms are behind — I need copy approved by Friday."},
    {"id":"together-sales-mid-07","level":"mid","profession":"sales","title":"The customer-exec email, integrated","scenario":"You're emailing a customer's CFO to request a renewal meeting. Integrate everything: lead with the ask, frame it in their terms (budget cycle), be concise, and give one concrete reason it's worth their time.","task":"Write the full 3-4 sentence email doing all of it.","tips":["Ask and 'why now' in the first sentence.","Frame the value in the CFO's terms, not yours.","One concrete reason the 30 minutes pays off."],"focus":["audience","concision"]},
    {"id":"together-sales-mid-08","level":"mid","profession":"sales","title":"The deal-review summary, complete","scenario":"You're summarizing a deal review for the rep and your VP. It must lead with the verdict, be precise about what's confirmed versus your read, own a recommendation, and stay short enough to actually be read.","task":"Write the 4-sentence summary: verdict, confirmed facts, your read, recommendation.","tips":["Verdict first, then separate fact from your read.","Keep it to what changes what the rep does next.","End on the owned recommendation and one action."],"focus":["structure","precision"]},
    {"id":"together-sales-mid-09","level":"mid","profession":"sales","title":"The coaching note that does it all","scenario":"You're writing a coaching note after a rep's call. It should be specific (behavior → impact → ask), kind but clear, concise, and end with one practiceable action — not a vague 'keep it up.'","task":"Write the full coaching note in 3-4 sentences integrating all of it.","tips":["One behavior, its impact, one specific ask.","Kind and clear together — name the fix plainly.","End with something they can practice this week."],"focus":["clarity","precision"]},
    {"id":"together-sales-mid-10","level":"mid","profession":"sales","title":"The all-hands two minutes","scenario":"You have two minutes at the all-hands to present the quarter's biggest win to a mixed audience. Integrate: audience-first (no jargon), a story arc, precise numbers, and a confident close that credits the team.","task":"Write the 4-5 sentence all-hands segment doing all of it.","tips":["Strip jargon for the non-sales room.","Tell it as a short arc, not a stat dump.","Close with a confident line and real credit."],"focus":["audience","impact"]},
    {"id":"together-sales-mid-11","level":"mid","profession":"sales","title":"The budget-shift proposal, whole","scenario":"You're proposing to move $80k from events to search. Integrate everything: lead with the recommendation, frame it with SCQA, use precise ROI numbers, pre-empt the CMO's attachment to events, and own the call.","task":"Write the proposal's opening and core in 4-5 sentences integrating all of it.","tips":["Recommend up front, then the SCQA logic.","Precise figures for both channels.","Pre-empt the emotional attachment before it surfaces."],"focus":["structure","impact"]},
    {"id":"together-sales-mid-12","level":"mid","profession":"sales","title":"The hard message, fully handled","scenario":"You're telling a rep they're going on a performance plan. Integrate: front-load the news (clear is kind), be precise with the evidence, use behavior → impact → ask, and hold presence without groveling.","task":"Write the full 4-sentence delivery integrating all of it.","tips":["News first, plainly, then the specific evidence.","Behavior, impact, and the ask in the plan.","Steady presence — no over-apologizing."],"focus":["clarity","impact"]},
    {"id":"together-sales-mid-13","level":"mid","profession":"sales","title":"The 30-second hallway answer","scenario":"Your CRO catches you in the hallway: 'Quick — how's the quarter looking?' You have 30 seconds. Integrate: answer first, one number, one risk, and a confident close, all spoken and tight.","task":"Write the 2-3 sentence spoken answer that lands all of it in 30 seconds.","tips":["Verdict and number in the first breath.","One risk, named specifically.","Close with confidence, not a trailing hedge."],"focus":["concision","impact"],"placeholder":"On track — commit's at $1.6M, holding. One risk is Meridian slipping; I'll know by Thursday."},
    {"id":"together-sales-mid-14","level":"mid","profession":"sales","title":"The launch coordination note to product","scenario":"You're aligning with product on the launch under a tight timeline. Integrate: lead with what you need, frame it in their terms, be precise about dates, and pre-empt their capacity objection.","task":"Write the 3-4 sentence coordination note doing all of it.","tips":["Lead with the specific ask and the date.","Frame it around the shared launch goal.","Pre-empt 'we don't have bandwidth' with the minimal version."],"focus":["audience","precision"]},
    {"id":"together-sales-mid-15","level":"mid","profession":"sales","title":"The quota conversation, integrated","scenario":"You're delivering a raised quota to a rep. Integrate everything: state the number plainly (clear is kind), frame it from their side (achievability), own it with presence, and answer the pushback with specifics.","task":"Write the 4-sentence conversation opening integrating all of it.","tips":["State the number without apology.","Frame achievability from their perspective immediately.","Have the specific support ready for the pushback."],"focus":["clarity","audience"]},
    {"id":"together-sales-mid-16","level":"mid","profession":"sales","title":"Edit the proposal's opening","scenario":"Your proposal opens: 'In today's rapidly evolving and increasingly competitive market landscape, organizations like yours are facing unprecedented challenges when it comes to optimizing their sales operations...' A buyer would stop reading. Fix it.","task":"Rewrite the opening as a reader would want: lead with their specific problem, concise, no filler.","tips":["Cut the market-landscape throat-clearing entirely.","Open on their actual, specific problem.","Read it as a busy buyer would — earn sentence two."],"focus":["concision","audience"]},
    {"id":"together-sales-mid-17","level":"mid","profession":"sales","title":"The board-slide notes, complete","scenario":"You're writing the speaker notes for your one marketing board slide. Integrate: an asserting headline, precise supporting numbers, a governing idea, and a confident owned takeaway — in the register a board expects.","task":"Write the headline and the 3-sentence speaker note integrating all of it.","tips":["Headline asserts; notes support with numbers.","One governing idea the whole slide serves.","Board register: assertion, evidence, implication."],"focus":["structure","impact"]},
    {"id":"together-sales-mid-18","level":"mid","profession":"sales","title":"The mixed-news update to leadership","scenario":"Pipeline is up 30% but a key deal just died. You need to deliver both to leadership: lead with the net, be precise, separate fact from read, own the implication, and stay composed about the loss.","task":"Write the 3-4 sentence update integrating the good and bad honestly.","tips":["Lead with the net position, then the two moving parts.","Precise numbers for both the up and the down.","Own what it means without spin or panic."],"focus":["precision","impact"]},
    {"id":"together-sales-mid-19","level":"mid","profession":"sales","title":"The reference-story writeup, whole","scenario":"Marketing wants a customer win story from you. Integrate: a story arc (before/turn/after), precise numbers, audience-appropriate language for prospects, and concision — a version a prospect would actually finish.","task":"Write the full 3-4 sentence reference story integrating all of it.","tips":["Before, turn, after — with a number in the after.","Language a prospect (not an insider) understands.","Tight enough that they read to the end."],"focus":["impact","concision"]},
    {"id":"together-sales-mid-20","level":"mid","profession":"sales","title":"The cross-team no, fully handled","scenario":"Marketing asks your team to take on an unplanned project that would hurt quota focus. Integrate: a clean no, the honest tradeoff, respect for the relationship, concision, and an alternative if one exists.","task":"Write the 3-sentence response integrating the clean no with the relationship intact.","tips":["Say no clearly, then the honest reason.","Keep it warm and short — no resentment, no waffle.","Offer a smaller or later version if you can."],"focus":["clarity","audience"]},
    {"id":"together-sales-mid-21","level":"mid","profession":"sales","title":"The at-risk-account escalation, complete","scenario":"A top account is wobbling and you need your SVP to act this week. Integrate everything: lead with the ask, quantify the risk precisely, structure situation/impact/ask, and make the stakes vivid enough to earn priority.","task":"Write the full 4-sentence escalation integrating all of it.","tips":["Ask and deadline first, then the sized risk.","Situation and impact, one line each.","Make the stakes concrete enough to jump the queue."],"focus":["structure","impact"]},
    {"id":"together-sales-mid-22","level":"mid","profession":"sales","title":"The forecast defense under fire","scenario":"The CFO doubts your commit. Integrate: answer the doubt directly, hold the number with evidence, separate fact from read, stay composed under pressure, and close by owning your number.","task":"Write the 3-4 sentence defense integrating all of it.","tips":["Answer the doubt head-on, then the evidence.","Distinguish confirmed facts from your read.","Hold the number calmly; own it at the close."],"focus":["clarity","precision"]},
    {"id":"together-sales-mid-23","level":"mid","profession":"sales","title":"The team kickoff open, integrated","scenario":"You're opening the H2 kickoff. Integrate: one governing theme, audience-first framing for your reps, a narrative that motivates, precise targets, and a confident presence that sets the tone.","task":"Write the 4-5 sentence kickoff opening integrating all of it.","tips":["One theme the whole talk hangs on.","Frame it around what's in it for the reps.","Precise targets, motivating arc, confident close."],"focus":["impact","clarity"]},
    {"id":"together-sales-mid-24","level":"mid","profession":"sales","title":"Match register: customer vs internal","scenario":"You have the same delay news to deliver to the customer and to your internal team. The customer version is careful and reassuring; the internal version is blunt and action-focused. Same facts, two registers.","task":"Write the 2-sentence customer version and the 2-sentence internal version of the delay.","tips":["Customer: reassure, protect their go-live, no internal blame.","Internal: blunt cause, clear owner, next action.","Match tone and detail to who's reading."],"focus":["audience","clarity"]},
    {"id":"together-sales-mid-25","level":"mid","profession":"sales","title":"The one-message-does-everything test","scenario":"Your CRO asks for a single Slack message summarizing the quarter for them to forward to the CEO. It must lead with the result, be precise, carry one governing idea, own an implication, and read cleanly at CEO altitude — all in a few lines.","task":"Write the full message integrating everything, in 3-4 tight sentences.","tips":["Lead with the result at CEO altitude — no weeds.","One governing idea, precise numbers, owned implication.","Write it to survive being forwarded without edits."],"focus":["structure","concision"],"placeholder":"We closed at 104% of plan on a stronger deal mix — win rate held while average deal size rose 12%."}
  ]
};
